# ---------------------------------------------------------------------------
# data loaders


def hydrate_post_extras(conn: sqlite3.Connection, post_ids: list[str], current_user_id: str | None) -> dict[str, dict[str, Any]]:
    if not post_ids:
        return {}
    placeholders = ",".join("?" * len(post_ids))

    likes = {row["target_id"]: row["c"] for row in conn.execute(
        f"SELECT target_id, COUNT(*) AS c FROM interactions WHERE kind='like' AND target_id IN ({placeholders}) GROUP BY target_id",
        post_ids,
    )}
    reposts = {row["target_id"]: row["c"] for row in conn.execute(
        f"SELECT target_id, COUNT(*) AS c FROM interactions WHERE kind='repost' AND target_id IN ({placeholders}) GROUP BY target_id",
        post_ids,
    )}
    bookmarks = {row["target_id"]: row["c"] for row in conn.execute(
        f"SELECT target_id, COUNT(*) AS c FROM interactions WHERE kind='bookmark' AND target_id IN ({placeholders}) GROUP BY target_id",
        post_ids,
    )}
    comments = {row["post_id"]: row["c"] for row in conn.execute(
        f"SELECT post_id, COUNT(*) AS c FROM comments WHERE deleted_at IS NULL AND post_id IN ({placeholders}) GROUP BY post_id",
        post_ids,
    )}

    user_likes: set[str] = set()
    user_reposts: set[str] = set()
    user_bookmarks: set[str] = set()
    if current_user_id:
        for row in conn.execute(
            f"SELECT target_id, kind FROM interactions WHERE user_id=? AND target_id IN ({placeholders})",
            [current_user_id] + post_ids,
        ):
            if row["kind"] == "like":
                user_likes.add(row["target_id"])
            elif row["kind"] == "repost":
                user_reposts.add(row["target_id"])
            elif row["kind"] == "bookmark":
                user_bookmarks.add(row["target_id"])

    tags_by_post: dict[str, list[str]] = {pid: [] for pid in post_ids}
    for row in conn.execute(
        f"SELECT post_id, tag FROM post_tags WHERE post_id IN ({placeholders})",
        post_ids,
    ):
        tags_by_post.setdefault(row["post_id"], []).append(row["tag"])

    media_by_post: dict[str, list[dict[str, Any]]] = {pid: [] for pid in post_ids}
    for row in conn.execute(
        f"""SELECT pm.post_id, pm.sort_index, pm.sort_order, pm.media_type AS pm_media_type,
                   pm.is_cover, pm.thumbnail_file_id, pm.duration_seconds,
                   pm.width AS pm_width, pm.height AS pm_height,
                   pm.processing_status, m.*
            FROM post_media pm JOIN media m ON m.id = pm.media_id
            WHERE pm.post_id IN ({placeholders}) AND m.deleted_at IS NULL
            ORDER BY COALESCE(NULLIF(pm.sort_order, 0), pm.sort_index), pm.sort_index""",
        post_ids,
    ):
        item = serialize_media(dict(row))
        item["type"] = row["pm_media_type"] or item["type"]
        item["media_type"] = item["type"]
        item["is_cover"] = bool(row["is_cover"])
        item["thumbnail_file_id"] = row["thumbnail_file_id"] or ""
        item["duration"] = float(row["duration_seconds"] or item.get("duration") or 0)
        item["duration_seconds"] = item["duration"]
        item["width"] = int(row["pm_width"] or item.get("width") or 0)
        item["height"] = int(row["pm_height"] or item.get("height") or 0)
        item["processing_status"] = row["processing_status"] or "ready"
        media_by_post.setdefault(row["post_id"], []).append(item)

    poll_by_post: dict[str, dict[str, Any]] = {}
    poll_rows = list(conn.execute(
        f"SELECT id, attributes FROM posts WHERE content_type = 'poll' AND id IN ({placeholders})",
        post_ids,
    ))
    poll_ids: list[str] = []
    for row in poll_rows:
        attrs = decode_post_attributes(row["attributes"])
        options = poll_options_from_attributes(attrs)
        if not options:
            continue
        pid = row["id"]
        poll_ids.append(pid)
        poll_by_post[pid] = {
            "options": options,
            "counts": [0 for _ in options],
            "total": 0,
            "my_vote": None,
            "closed": poll_is_closed(attrs.get("expires_at")),
            "expires_at": str(attrs.get("expires_at") or ""),
        }
    if poll_ids:
        poll_placeholders = ",".join("?" * len(poll_ids))
        for row in conn.execute(
            f"""SELECT post_id, option_index, COUNT(*) AS c
                FROM post_poll_votes
                WHERE post_id IN ({poll_placeholders})
                GROUP BY post_id, option_index""",
            poll_ids,
        ):
            payload = poll_by_post.get(row["post_id"])
            if not payload:
                continue
            idx = int(row["option_index"])
            if 0 <= idx < len(payload["counts"]):
                payload["counts"][idx] = int(row["c"])
        if current_user_id:
            for row in conn.execute(
                f"""SELECT post_id, option_index
                    FROM post_poll_votes
                    WHERE user_id = ? AND post_id IN ({poll_placeholders})""",
                [current_user_id] + poll_ids,
            ):
                payload = poll_by_post.get(row["post_id"])
                if payload:
                    payload["my_vote"] = int(row["option_index"])
        for payload in poll_by_post.values():
            payload["total"] = int(sum(payload["counts"]))

    extras: dict[str, dict[str, Any]] = {}
    for pid in post_ids:
        extras[pid] = {
            "like_count": likes.get(pid, 0),
            "repost_count": reposts.get(pid, 0),
            "bookmark_count": bookmarks.get(pid, 0),
            "comment_count": comments.get(pid, 0),
            "liked": pid in user_likes,
            "reposted": pid in user_reposts,
            "bookmarked": pid in user_bookmarks,
            "can_interact": bool(current_user_id),
            "viewer": {"id": current_user_id} if current_user_id else None,
            "tags": tags_by_post.get(pid, []),
            "media": media_by_post.get(pid, []),
            "poll": poll_by_post.get(pid),
        }
    return extras


def fetch_users_by_ids(conn: sqlite3.Connection, user_ids: list[str]) -> dict[str, dict[str, Any]]:
    if not user_ids:
        return {}
    placeholders = ",".join("?" * len(user_ids))
    result: dict[str, dict[str, Any]] = {}
    for row in conn.execute(f"SELECT * FROM users WHERE id IN ({placeholders})", user_ids):
        result[row["id"]] = serialize_user(dict(row))
    return result


def fetch_posts_with_extras(conn: sqlite3.Connection, post_rows: list[dict[str, Any]], current_user_id: str | None) -> list[dict[str, Any]]:
    if not post_rows:
        return []
    ids = [r["id"] for r in post_rows]
    extras_map = hydrate_post_extras(conn, ids, current_user_id)
    repost_ids = [r["repost_of_id"] for r in post_rows if r.get("repost_of_id")]
    originals: dict[str, dict[str, Any]] = {}
    if repost_ids:
        placeholders = ",".join("?" * len(repost_ids))
        rows = list(conn.execute(f"SELECT * FROM posts WHERE id IN ({placeholders})", repost_ids))
        og_ids = [r["id"] for r in rows]
        og_extras = hydrate_post_extras(conn, og_ids, current_user_id)
        author_ids = [r["author_id"] for r in rows]
        author_map = fetch_users_by_ids(conn, author_ids)
        for r in rows:
            entry = dict(r)
            originals[entry["id"]] = serialize_post(entry, {**og_extras.get(entry["id"], {}), "author": author_map.get(entry["author_id"])})

    author_ids = list({r["author_id"] for r in post_rows})
    author_map = fetch_users_by_ids(conn, author_ids)

    posts: list[dict[str, Any]] = []
    for r in post_rows:
        entry = dict(r)
        extras = dict(extras_map.get(entry["id"], {}))
        extras["author"] = author_map.get(entry["author_id"])
        if entry.get("repost_of_id"):
            extras["original_post"] = originals.get(entry["repost_of_id"])
        posts.append(serialize_post(entry, extras))
    return posts


def normalize_listing_type(value: Any) -> str:
    raw = str(value or "").strip().lower()
    aliases = {
        "market": "secondhand",
        "marketplace": "secondhand",
        "second_hand": "secondhand",
        "housing": "rental",
        "rent": "rental",
        "rentals": "rental",
        "job_seek": "job",
        "jobs": "job",
        "job_post": "hiring",
        "recruiting": "hiring",
        "service": "local_service",
        "services": "local_service",
        "coupon": "discount",
        "deals": "discount",
    }
    raw = aliases.get(raw, raw)
    return raw if raw in LISTING_TYPES else "secondhand"


def normalize_listing_status(value: Any, fallback: str = "published") -> str:
    raw = str(value or "").strip().lower()
    return raw if raw in LISTING_STATUSES else fallback


def normalize_listing_verification(value: Any, fallback: str = "unverified") -> str:
    raw = str(value or "").strip().lower()
    return raw if raw in LISTING_VERIFICATION_STATUSES else fallback


def normalize_listing_inquiry_status(value: Any, fallback: str = "new") -> str:
    raw = str(value or "").strip().lower()
    if raw == "open":
        raw = "new"
    return raw if raw in LISTING_INQUIRY_STATUSES else fallback


def normalize_listing_promotion_type(value: Any, fallback: str = "top") -> str:
    raw = str(value or "").strip().lower()
    aliases = {
        "pinned": "top",
        "pin": "top",
        "boost": "featured",
        "homepage": "city_home",
        "city_home_recommend": "city_home",
        "category": "category_featured",
        "urgent": "urgent_hiring",
        "rental": "recommended_rental",
        "service": "recommended_service",
    }
    raw = aliases.get(raw, raw)
    return raw if raw in LISTING_PROMOTION_TYPES else fallback


def normalize_listing_verification_type(value: Any, fallback: str = "seller") -> str:
    raw = str(value or "").strip().lower()
    aliases = {
        "recruiter_verified": "recruiter",
        "rental": "rental_provider",
        "service": "service_provider",
        "merchant": "business",
    }
    raw = aliases.get(raw, raw)
    return raw if raw in LISTING_VERIFICATION_TYPES else fallback


def listing_value_type(value: Any) -> str:
    if isinstance(value, bool):
        return "bool"
    if isinstance(value, int) and not isinstance(value, bool):
        return "int"
    if isinstance(value, float):
        return "float"
    return "string"


def listing_value_to_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, (int, float)):
        return str(value)
    return str(value).strip()[:1000]


def listing_text_to_value(value: str, value_type: str) -> Any:
    if value_type == "bool":
        return str(value).lower() in {"1", "true", "yes", "y", "on"}
    if value_type == "int":
        try:
            return int(float(value))
        except Exception:
            return 0
    if value_type == "float":
        try:
            return float(value)
        except Exception:
            return 0.0
    return value


def normalize_listing_attributes(listing_type: str, raw: Any) -> dict[str, tuple[str, str]]:
    if not isinstance(raw, dict):
        return {}
    allowed = LISTING_ATTRIBUTE_KEYS.get(listing_type, set())
    out: dict[str, tuple[str, str]] = {}
    for key, value in raw.items():
        k = str(key or "").strip()
        if not k or (allowed and k not in allowed):
            continue
        text = listing_value_to_text(value)
        if text == "":
            continue
        out[k] = (text, listing_value_type(value))
    return out


def public_listing_title(title: Any) -> str:
    text = str(title or "")
    return (
        text
        .replace("，外国人可咨询", "，可预约看房")
        .replace("外国人可咨询", "可预约看房")
        .replace("，外国人可", "")
        .replace("外国人可", "")
        .strip()
    )


def public_listing_attributes(listing_type: str, attrs: Any) -> dict[str, Any]:
    if not isinstance(attrs, dict):
        return {}
    cleaned = dict(attrs)
    if listing_type == "rental":
        cleaned.pop("foreigners_allowed", None)
    return cleaned


def listing_image_fallback(listing_type: str, index: int = 0) -> str:
    if listing_type == "rental":
        seed = ["apartment", "interior", "japan-home"][index % 3]
    elif listing_type in {"job", "hiring"}:
        seed = ["workplace", "restaurant-job", "office"][index % 3]
    elif listing_type == "local_service":
        seed = ["service", "moving", "repair"][index % 3]
    elif listing_type == "discount":
        seed = ["local-shop", "coupon", "cafe"][index % 3]
    else:
        seed = ["keyboard", "chair", "camera"][index % 3]
    return f"https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=900&q=80&auto=format&fit=crop&ixid=machi-{seed}"


def listing_policy_violation(title: str, description: str, category: str = "") -> str:
    text = f"{title} {description} {category}".lower()
    blocked_terms = [
        "成人", "adult", "药品", "毒品", "drug", "武器", "weapon", "烟草", "tobacco",
        "酒精", "alcohol", "假冒", "fake", "金融产品", "贷款", "个人信息", "身份证",
        "黄牛", "票务黄牛", "伴游", "灰产", "保证金", "押金兼职", "培训费",
    ]
    if any(term in text for term in blocked_terms):
        return "该内容可能涉及禁用品类或高风险交易，不能发布为城市信息。"
    return ""


def resolve_listing_owner_update_publication(
    conn: sqlite3.Connection,
    user: dict[str, Any],
    row: sqlite3.Row | dict[str, Any],
    *,
    requested_status: str | None,
    content_changed: bool,
) -> dict[str, Any]:
    """Resolve owner-visible listing status without allowing review bypasses."""
    current = dict(row)
    current_status = normalize_listing_status(current.get("status"), "draft")
    target_status = requested_status or current_status
    if target_status not in PUBLIC_LISTING_STATUSES:
        return {"status": target_status}

    needs_review_check = content_changed or current_status not in PUBLIC_LISTING_STATUSES
    if not needs_review_check:
        return {"status": target_status}

    requires_review, review_reason = reputation_validate_listing_publish(
        conn,
        user,
        normalize_listing_type(current.get("type")),
    )
    review_enabled = _site_settings(conn).get("listing_review_enabled", "1") != "0"
    if review_enabled and requires_review:
        return {
            "status": "pending_review",
            "verification_status": "pending",
            "published_at": None,
            "requires_review": True,
            "review_reason": review_reason,
        }
    return {
        "status": target_status,
        "verification_status": "unverified",
        "published_at": current.get("published_at") or now_iso(),
        "requires_review": False,
        "review_reason": "",
    }


def validate_listing_media_for_create(
    conn: sqlite3.Connection,
    user_id: str,
    listing_type: str,
    data: dict[str, Any],
) -> list[dict[str, Any]]:
    legacy_media = data.get("media") or data.get("media_urls") or []
    if isinstance(legacy_media, list) and any(item for item in legacy_media):
        raise APIError("请先通过统一上传接口上传图片", 400, "unified_upload_required")

    raw_media_ids = data.get("media_ids")
    if raw_media_ids is None:
        raw_media_ids = data.get("mediaIds") or []
    if not isinstance(raw_media_ids, list):
        raise APIError("媒体文件格式不正确", 400, "invalid_media_ids")

    media_limit = upload_count_limit_for_listing(listing_type)
    submitted = [str(value or "").strip() for value in raw_media_ids if str(value or "").strip()]
    if len(submitted) > media_limit:
        raise APIError("图片数量超过限制", 400, "listing_media_limit")

    expected_purpose = LISTING_PURPOSE_BY_TYPE.get(listing_type, "secondhand_image")
    valid_media: list[dict[str, Any]] = []
    seen: set[str] = set()
    for media_id in submitted:
        if media_id in seen:
            continue
        seen.add(media_id)
        media_row = conn.execute(
            """
            SELECT m.*
              FROM media m
              JOIN uploaded_files f ON f.id = m.id
             WHERE m.id = ?
               AND m.owner_id = ?
               AND m.deleted_at IS NULL
               AND f.user_id = ?
               AND f.deleted_at IS NULL
               AND f.status = 'ready'
               AND f.purpose = ?
             LIMIT 1
            """,
            (media_id, user_id, user_id, expected_purpose),
        ).fetchone()
        if not media_row:
            raise APIError("包含无权使用或尚未完成的媒体文件", 403, "listing_media_forbidden")
        valid_media.append(dict(media_row))
    return valid_media


