    def api_feed(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_payload = {"id": viewer_id} if viewer_id else None
        can_interact = bool(viewer_id)
        mode = (query.get("mode") or "recommend").strip().lower()
        if mode not in {"recommend", "plaza", "local", "following", "hot"}:
            mode = "recommend"
        limit = max(1, min(int(query.get("limit") or 20), 50))
        cursor = cursor_decode(query.get("cursor"))

        blocked_clause = ""
        blocked_params: list[Any] = []
        if viewer_id:
            blocked_clause = " AND p.author_id NOT IN (SELECT blocked_id FROM blocks WHERE blocker_id = ?)"
            blocked_params.append(viewer_id)

        type_clause = ""
        type_params: list[Any] = []
        raw_types = query.get("content_type") or query.get("content_types") or ""
        content_types = [normalize_content_type(v) for v in raw_types.split(",") if v.strip()]
        content_types = [v for v in dict.fromkeys(content_types) if v in CONTENT_TYPES]
        if mode == "plaza" and not content_types:
            content_types = [
                "dynamic", "local_info", "guide", "question", "rant",
                "meetup", "dining", "event", "warning",
            ]
        if content_types:
            type_clause = " AND p.content_type IN (%s)" % ",".join("?" * len(content_types))
            type_params.extend(content_types)
        else:
            # Keep the home/recommend/local feed a community timeline.
            # High-intent marketplace/rental/job rows now live in
            # city_listings; legacy typed posts are hidden from generic feeds
            # unless a channel explicitly asks for them.
            type_clause = " AND p.content_type NOT IN (%s)" % ",".join("?" * len(HIGH_INTENT_POST_TYPES))
            type_params.extend(sorted(HIGH_INTENT_POST_TYPES))

        region_clause = ""
        region_params: list[Any] = []
        req_region_code = (query.get("region_code") or "").strip().lower()
        req_country  = (query.get("country")  or "").strip().lower()
        req_province = (query.get("province") or "").strip().lower()
        req_city     = (query.get("city")     or "").strip().lower()

        if mode == "local" and not (req_region_code or req_city) and viewer:
            viewer_row = conn.execute(
                "SELECT country, province, city, current_region_code FROM users WHERE id = ?",
                (viewer["user_id"],),
            ).fetchone()
            if viewer_row:
                req_region_code = (viewer_row["current_region_code"] or "").lower()
                req_country  = (viewer_row["country"] or "").lower()
                req_province = (viewer_row["province"] or "").lower()
                req_city     = (viewer_row["city"] or "").lower()

        if req_region_code:
            region_clause = " AND p.region_code = ?"
            region_params.append(req_region_code)
        elif req_country or req_city:
            clauses = []
            if req_country:
                clauses.append("p.country = ?")
                region_params.append(req_country)
            if req_province:
                clauses.append("p.province = ?")
                region_params.append(req_province)
            if req_city:
                clauses.append("p.city = ?")
                region_params.append(req_city)
            region_clause = " AND " + " AND ".join(clauses)

        if mode == "local" and not (req_region_code or req_city):
            raise APIError("city required", 400, "missing_region")

        if mode == "following":
            if not viewer_id:
                raise APIError("请登录后继续", 401, "AUTH_REQUIRED")
            base = """
                SELECT p.* FROM posts p
                JOIN follows f ON f.following_id = p.author_id
                WHERE f.follower_id = ? AND p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
            """
            base_params: list[Any] = [viewer_id]
        elif mode == "local":
            base = f"""
                SELECT p.* FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
            """
            base_params = []
        elif mode == "hot":
            cutoff_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
            # Verified members get a gentle ranking nudge (VERIFIED_BOOST_SCORE,
            # ~1.05). Applied only to the hot-feed ORDER BY — the displayed
            # heat_score is unchanged, so it never overpowers real engagement.
            sql = f"""
                SELECT p.*, {_heat_score_sql('p')} AS computed_heat,
                       COALESCE((SELECT u.is_verified_member FROM users u WHERE u.id = p.author_id), 0) AS author_vm
                FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
                  AND p.created_at >= ?
                  {region_clause}
                  {type_clause}
                  {blocked_clause}
                ORDER BY (computed_heat * (CASE WHEN author_vm = 1 THEN ? ELSE 1.0 END)) DESC, p.created_at DESC
                LIMIT ?
            """
            rows = list(conn.execute(sql, [cutoff_24h, *region_params, *type_params, *blocked_params, VERIFIED_BOOST_SCORE, limit]))
            posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
            self.send_json({"items": posts, "next_cursor": None, "mode": mode, "viewer": viewer_payload, "canInteract": can_interact, "can_interact": can_interact})
            return
        else:
            base = """
                SELECT p.* FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
            """
            base_params = []

        cursor_clause = ""
        cursor_params: list[Any] = []
        if cursor:
            cursor_clause = " AND (p.created_at, p.id) < (?, ?)"
            cursor_params.extend([cursor[0], cursor[1]])

        sql = base + region_clause + type_clause + blocked_clause + cursor_clause + " ORDER BY p.created_at DESC, p.id DESC LIMIT ?"
        params = [*base_params, *region_params, *type_params, *blocked_params, *cursor_params]
        params.append(limit + 1)
        rows = list(conn.execute(sql, params))

        next_cursor = None
        if len(rows) > limit:
            extra = rows.pop()
            next_cursor = cursor_encode(extra["created_at"], extra["id"])
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        self.send_json({"items": posts, "next_cursor": next_cursor, "mode": mode, "viewer": viewer_payload, "canInteract": can_interact, "can_interact": can_interact})

    def api_create_post(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        content = (data.get("content") or "").strip()
        media_ids = data.get("media_ids") or []
        repost_of_id = data.get("repost_of_id")
        # Content type + typed attributes. Validated + truncated
        # server-side so a client can't push junk into untyped JSON
        # storage. Typed posts may be form-first and have very short
        # body text, so attributes count as content for emptiness.
        content_type = normalize_content_type(data.get("content_type"))
        # Machi Verified gate. High-trust types (招聘/租房/找室友/本地服务/
        # 商家/优惠/内推) require an active membership. Enforced here for
        # EVERY client — the apps only mirror it for UX; a raw API call
        # cannot bypass it. Ordinary content (dynamic/question/guide/二手/
        # 小组/美食/活动…) is untouched and stays free.
        require_verified_membership(conn, user["id"], content_type)
        # Daily publish cap. 0 == off (default) so ordinary posting is
        # never impeded; members get the higher ceiling when an operator
        # opts in via the env config.
        _daily_limit = MEMBERSHIP_DAILY_LIMIT_FREE
        if _daily_limit > 0 and has_active_membership(conn, user["id"]):
            _daily_limit = MEMBERSHIP_DAILY_LIMIT_VERIFIED or 0
        if _daily_limit > 0:
            _since = (datetime.now(timezone.utc) - timedelta(days=1)).isoformat()
            _today = conn.execute(
                "SELECT COUNT(*) AS c FROM posts WHERE author_id = ? AND created_at >= ? AND deleted_at IS NULL",
                (user["id"], _since),
            ).fetchone()["c"]
            if int(_today) >= _daily_limit:
                raise APIError("今日发布已达上限，开通 Machi 认证会员可提升额度。", 429, "daily_limit_reached")
        attributes   = normalize_post_attributes(content_type, data.get("attributes"))
        if content_type == "poll":
            poll_attrs = decode_post_attributes(attributes)
            if not str(poll_attrs.get("question") or "").strip() or len(poll_options_from_attributes(poll_attrs)) < 2:
                raise APIError("投票需要问题和至少两个选项", 400, "invalid_poll")
        if not content and not media_ids and not repost_of_id and not attributes:
            raise APIError("内容不能为空", 400, "empty_content")
        if len(content) > 2000:
            raise APIError("内容过长", 400, "content_too_long")
        valid_media: list[dict[str, Any]] = []
        image_count = 0
        video_count = 0
        for raw_media_id in media_ids[:10]:
            media_id = str(raw_media_id or "").strip()
            if not media_id:
                continue
            media_row = conn.execute(
                "SELECT * FROM media WHERE id = ? AND owner_id = ? AND deleted_at IS NULL",
                (media_id, user["id"]),
            ).fetchone()
            if not media_row:
                raise APIError("包含无权使用的媒体文件", 403, "media_forbidden")
            media_type = str(media_row["type"] or "image")
            if media_type == "video":
                video_count += 1
                if video_count > 1:
                    raise APIError("每个帖子最多上传 1 个视频", 400, "post_video_limit")
            elif media_type == "image":
                image_count += 1
                if image_count > 9:
                    raise APIError("每个帖子最多上传 9 张图片", 400, "post_image_limit")
            valid_media.append(dict(media_row))
        # Region — client may pass any of (country, province, city) or
        # the resolved region_code. We canonicalise here so the row is
        # internally consistent and the index hits.
        country  = (data.get("country")  or user.get("country")  or "").strip().lower()
        province = (data.get("province") or user.get("province") or "").strip().lower()
        city     = (data.get("city")     or user.get("city")     or "").strip().lower()
        region_code = (data.get("region_code") or "").strip().lower()
        if not region_code:
            region_code = _resolve_region_code(country, province, city)
        elif not country:
            country, province, city = _parse_region_code(region_code)
        post_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO posts (id, author_id, content, repost_of_id, view_count, status, country, province, city, region_code, content_type, attributes, created_at, updated_at) VALUES (?, ?, ?, ?, 1, 'active', ?, ?, ?, ?, ?, ?, ?, ?)",
            (post_id, user["id"], content, repost_of_id, country, province, city, region_code, content_type, attributes, now_iso(), now_iso()),
        )
        for tag in extract_tags(content):
            conn.execute("INSERT OR IGNORE INTO post_tags VALUES (?, ?)", (post_id, tag))
        explicit_tags = data.get("tags") or []
        for tag in explicit_tags:
            normalized = str(tag).strip().lstrip("#").lower()
            if normalized:
                conn.execute("INSERT OR IGNORE INTO post_tags VALUES (?, ?)", (post_id, normalized))
        for index, media_item in enumerate(valid_media):
            media_id = media_item["id"]
            media_type = media_item.get("type") or "image"
            processing_status = "pending" if media_type == "video" else "ready"
            conn.execute(
                """
                INSERT INTO post_media (
                    id, post_id, media_id, uploaded_file_id, media_type, sort_index, sort_order, is_cover,
                    duration_seconds, width, height, processing_status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    str(uuid.uuid4()), post_id, media_id, media_id, media_type, index, index,
                    1 if index == 0 else 0,
                    float(media_item.get("duration") or 0), int(media_item.get("width") or 0), int(media_item.get("height") or 0),
                    processing_status, now_iso(), now_iso(),
                ),
            )
            conn.execute(
                "UPDATE uploaded_files SET entity_type = 'post', entity_id = ?, updated_at = ? WHERE id = ? AND user_id = ?",
                (post_id, now_iso(), media_id, user["id"]),
            )
        if content_type not in HIGH_INTENT_POST_TYPES:
            reputation_apply_event(conn, user["id"], "first_post", target_kind="post", target_id=post_id)
            reputation_apply_event(
                conn,
                user["id"],
                reputation_rule_for_post_type(content_type),
                target_kind="post",
                target_id=post_id,
                metadata={"content_type": content_type},
            )
        if repost_of_id:
            original = conn.execute("SELECT author_id FROM posts WHERE id = ?", (repost_of_id,)).fetchone()
            if original and original["author_id"] != user["id"]:
                conn.execute(
                    "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, content, created_at) VALUES (?, ?, ?, 'repost', ?, ?, ?)",
                    (str(uuid.uuid4()), original["author_id"], user["id"], repost_of_id, content, now_iso()),
                )
                HUB.publish(original["author_id"], {"type": "notification", "kind": "repost"})
        row = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [row], user["id"])
        HUB.broadcast([user["id"]], {"type": "post_created", "post_id": post_id})
        # Drop derived caches so the new post shows up on hot / trending
        # without waiting for the 30s TTL.
        _cache_invalidate("feed:hot")
        _cache_invalidate("trending:")
        self.send_json({"post": posts[0]})

    def api_post_detail(self, conn: sqlite3.Connection, post_id: str) -> None:
        viewer = self.current_session(conn)
        row = conn.execute("SELECT * FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        row_dict_value = dict(row)
        viewer_id = viewer["user_id"] if viewer else None
        if row_dict_value.get("status") not in VISIBLE_POST_STATUSES and row_dict_value.get("author_id") != viewer_id:
            viewer_user = conn.execute("SELECT role FROM users WHERE id = ?", (viewer_id,)).fetchone() if viewer_id else None
            if not viewer_user or viewer_user["role"] != "admin":
                raise APIError("帖子不存在", 404, "post_not_found")
        posts = fetch_posts_with_extras(conn, [row_dict_value], viewer_id)
        self.send_json({"post": posts[0], "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_edit_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        if row["author_id"] != user["id"]:
            raise APIError("只能编辑自己的帖子", 403, "forbidden")
        data = self.read_json()
        if "content" in data:
            content = (data["content"] or "").strip()
            conn.execute("UPDATE posts SET content = ?, updated_at = ? WHERE id = ?", (content, now_iso(), post_id))
            conn.execute("DELETE FROM post_tags WHERE post_id = ?", (post_id,))
            for tag in extract_tags(content):
                conn.execute("INSERT OR IGNORE INTO post_tags VALUES (?, ?)", (post_id, tag))
        # Allow editing the typed attributes blob (e.g. mark a
        # secondhand listing as sold, change a job's salary range).
        # `content_type` is intentionally immutable post-creation —
        # changing it would invalidate every cached card.
        if "attributes" in data:
            current_type = (conn.execute("SELECT content_type FROM posts WHERE id = ?", (post_id,)).fetchone() or {})
            ct = current_type["content_type"] if current_type else "dynamic"
            attrs = normalize_post_attributes(ct, data["attributes"])
            conn.execute("UPDATE posts SET attributes = ?, updated_at = ? WHERE id = ?", (attrs, now_iso(), post_id))
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_delete_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT author_id FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        if row["author_id"] != user["id"]:
            raise APIError("只能删除自己的帖子", 403, "forbidden")
        conn.execute("UPDATE posts SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?", (now_iso(), now_iso(), post_id))
        conn.execute(
            """
            UPDATE uploaded_files
               SET status = 'deleted', deleted_at = ?, updated_at = ?
             WHERE entity_type = 'post' AND entity_id = ? AND user_id = ? AND deleted_at IS NULL
            """,
            (now_iso(), now_iso(), post_id, user["id"]),
        )
        _cache_invalidate("feed:hot")
        _cache_invalidate("trending:")
        self.send_json({"ok": True})

    def api_post_interaction(self, conn: sqlite3.Connection, post_id: str, kind: str, on: bool) -> None:
        user = self.require_user(conn)
        post = conn.execute("SELECT author_id, content_type FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        existing = conn.execute(
            "SELECT id FROM interactions WHERE target_id = ? AND user_id = ? AND kind = ?",
            (post_id, user["id"], kind),
        ).fetchone()
        if on and not existing:
            conn.execute(
                "INSERT INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, ?, ?)",
                (str(uuid.uuid4()), post_id, user["id"], kind, now_iso()),
            )
            if kind == "bookmark":
                reputation_apply_event(
                    conn,
                    user["id"],
                    "first_bookmark",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                )
            if kind == "like" and post["author_id"] != user["id"]:
                reputation_apply_event(
                    conn,
                    post["author_id"],
                    "content_liked",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                    metadata={"content_type": post["content_type"] or "dynamic"},
                )
                conn.execute(
                    "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, content, created_at) VALUES (?, ?, ?, 'like', ?, '', ?)",
                    (str(uuid.uuid4()), post["author_id"], user["id"], post_id, now_iso()),
                )
                HUB.publish(post["author_id"], {"type": "notification", "kind": "like", "post_id": post_id})
            if kind == "bookmark" and post["author_id"] != user["id"]:
                reputation_apply_event(
                    conn,
                    post["author_id"],
                    "content_bookmarked",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                    metadata={"content_type": post["content_type"] or "dynamic"},
                )
        elif not on and existing:
            conn.execute("DELETE FROM interactions WHERE id = ?", (existing["id"],))
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_repost(self, conn: sqlite3.Connection, post_id: str, on: bool) -> None:
        user = self.require_user(conn)
        post = conn.execute("SELECT * FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        if on:
            try:
                conn.execute(
                    "INSERT INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, 'repost', ?)",
                    (str(uuid.uuid4()), post_id, user["id"], now_iso()),
                )
            except sqlite3.IntegrityError:
                pass
            if post["author_id"] != user["id"]:
                conn.execute(
                    "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, content, created_at) VALUES (?, ?, ?, 'repost', ?, '', ?)",
                    (str(uuid.uuid4()), post["author_id"], user["id"], post_id, now_iso()),
                )
                HUB.publish(post["author_id"], {"type": "notification", "kind": "repost"})
        else:
            conn.execute(
                "DELETE FROM interactions WHERE target_id = ? AND user_id = ? AND kind = 'repost'",
                (post_id, user["id"]),
            )
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_vote_poll(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        try:
            option_index = int(data.get("option_index"))
        except (TypeError, ValueError):
            raise APIError("请选择投票选项", 400, "invalid_poll_vote")
        post = conn.execute("SELECT * FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post or post["content_type"] != "poll":
            raise APIError("投票不存在", 404, "poll_not_found")
        attrs = decode_post_attributes(post["attributes"])
        options = poll_options_from_attributes(attrs)
        if not options:
            raise APIError("投票选项异常", 400, "invalid_poll")
        if poll_is_closed(attrs.get("expires_at")):
            raise APIError("投票已截止", 400, "poll_closed")
        if option_index < 0 or option_index >= len(options):
            raise APIError("投票选项不存在", 400, "invalid_poll_vote")
        conn.execute(
            """
            INSERT INTO post_poll_votes (post_id, user_id, option_index, created_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(post_id, user_id)
            DO UPDATE SET option_index = excluded.option_index, created_at = excluded.created_at
            """,
            (post_id, user["id"], option_index, now_iso()),
        )
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_view_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        # Throttle view bumps to once per (viewer, post, hour). The
        # previous behaviour let any client spam +1 forever, which
        # both inflated heat scores and gave authors a trivial way to
        # juice their own metrics.
        viewer = self.current_session(conn)
        key = f"view:{post_id}:{viewer['user_id'] if viewer else self._client_ip()}"
        if _cache_get(key) is None:
            conn.execute("UPDATE posts SET view_count = view_count + 1 WHERE id = ?", (post_id,))
            _cache_put(key, True, ttl_seconds=3600)
        self.send_json({"ok": True})

    def api_list_comments(self, conn: sqlite3.Connection, post_id: str, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        sort = query.get("sort") or "top"
        rows = list(conn.execute(
            "SELECT * FROM comments WHERE post_id = ? AND deleted_at IS NULL ORDER BY created_at DESC",
            (post_id,),
        ))
        ids = [r["id"] for r in rows]
        like_counts: dict[str, int] = {}
        liked_set: set[str] = set()
        if ids:
            placeholders = ",".join("?" * len(ids))
            for row in conn.execute(
                f"SELECT target_id, COUNT(*) AS c FROM interactions WHERE kind='commentLike' AND target_id IN ({placeholders}) GROUP BY target_id",
                ids,
            ):
                like_counts[row["target_id"]] = row["c"]
            if viewer_id:
                for row in conn.execute(
                    f"SELECT target_id FROM interactions WHERE kind='commentLike' AND user_id=? AND target_id IN ({placeholders})",
                    [viewer_id] + ids,
                ):
                    liked_set.add(row["target_id"])
        author_ids = list({r["author_id"] for r in rows})
        author_map = fetch_users_by_ids(conn, author_ids)
        comments = [
            serialize_comment(
                dict(r),
                {
                    "like_count": like_counts.get(r["id"], 0),
                    "liked": r["id"] in liked_set,
                    "author": author_map.get(r["author_id"]),
                },
            )
            for r in rows
        ]
        if sort == "top":
            comments.sort(key=lambda c: (c["like_count"], c["created_at"]), reverse=True)
        else:
            comments.sort(key=lambda c: c["created_at"], reverse=True)
        self.send_json({"items": comments, "next_cursor": None})

    def api_create_comment(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        content = (data.get("content") or "").strip()
        if not content:
            raise APIError("评论不能为空", 400, "empty_comment")
        if len(content) > 2000:
            raise APIError("评论过长", 400, "comment_too_long")
        post = conn.execute("SELECT author_id, content_type FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        comment_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO comments (id, post_id, author_id, content, parent_comment_id, reply_to_user_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
            (comment_id, post_id, user["id"], content, data.get("parent_comment_id"), data.get("reply_to_user_id"), now_iso(), now_iso()),
        )
        if post["author_id"] != user["id"]:
            reputation_apply_event(
                conn,
                post["author_id"],
                "content_commented",
                actor_user_id=user["id"],
                target_kind="post",
                target_id=post_id,
                metadata={"content_type": post["content_type"] or "dynamic"},
            )
            if (post["content_type"] or "") == "question" and len(content) >= 10:
                reputation_apply_event(
                    conn,
                    user["id"],
                    "comment_on_question",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                )
            ntype = "reply" if data.get("parent_comment_id") else "comment"
            conn.execute(
                "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, target_comment_id, content, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                (str(uuid.uuid4()), post["author_id"], user["id"], ntype, post_id, comment_id, content[:140], now_iso()),
            )
            HUB.publish(post["author_id"], {"type": "notification", "kind": ntype, "post_id": post_id})
        row = dict(conn.execute("SELECT * FROM comments WHERE id = ?", (comment_id,)).fetchone())
        comment = serialize_comment(row, {"author": serialize_user(user), "like_count": 0, "liked": False})
        self.send_json({"comment": comment})

    def api_delete_comment(self, conn: sqlite3.Connection, comment_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM comments WHERE id = ?", (comment_id,)).fetchone()
        if not row:
            raise APIError("评论不存在", 404, "comment_not_found")
        post = conn.execute("SELECT author_id FROM posts WHERE id = ?", (row["post_id"],)).fetchone()
        if row["author_id"] != user["id"] and (not post or post["author_id"] != user["id"]):
            raise APIError("无权删除", 403, "forbidden")
        conn.execute("UPDATE comments SET deleted_at = ?, updated_at = ? WHERE id = ?", (now_iso(), now_iso(), comment_id))
        self.send_json({"ok": True})

    def api_comment_like(self, conn: sqlite3.Connection, comment_id: str, on: bool) -> None:
        user = self.require_user(conn)
        existing = conn.execute(
            "SELECT id FROM interactions WHERE target_id = ? AND user_id = ? AND kind = 'commentLike'",
            (comment_id, user["id"]),
        ).fetchone()
        if on and not existing:
            conn.execute(
                "INSERT INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, 'commentLike', ?)",
                (str(uuid.uuid4()), comment_id, user["id"], now_iso()),
            )
        elif not on and existing:
            conn.execute("DELETE FROM interactions WHERE id = ?", (existing["id"],))
        self.send_json({"ok": True, "liked": on})

    def api_search(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        q = (query.get("q") or "").strip()
        kind = query.get("kind") or "all"
        if not q:
            self.send_json({"posts": [], "listings": [], "users": [], "topics": [], "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})
            return
        if viewer_id:
            conn.execute(
                "INSERT INTO search_history (id, user_id, query, created_at) VALUES (?, ?, ?, ?)",
                (str(uuid.uuid4()), viewer_id, q, now_iso()),
            )
        like = f"%{q}%"
        posts: list[dict[str, Any]] = []
        listings: list[dict[str, Any]] = []
        users: list[dict[str, Any]] = []
        topics: list[dict[str, Any]] = []
        if kind in ("all", "post"):
            country_clause = "AND country = ?" if viewer_country else ""
            params: tuple[Any, ...] = (like, like, like, like, like, like, viewer_country) if viewer_country else (like, like, like, like, like, like)
            rows = list(conn.execute(
                f"""
                SELECT * FROM posts
                WHERE deleted_at IS NULL
                  AND status IN ('published', 'active')
                  AND (content LIKE ? OR country LIKE ? OR province LIKE ? OR city LIKE ? OR content_type LIKE ? OR attributes LIKE ?)
                  {country_clause}
                ORDER BY created_at DESC LIMIT 30
                """,
                params,
            ))
            posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        if kind in ("all", "listing", "listings", "secondhand", "rental", "job"):
            country_clause = "AND country_code = ?" if viewer_country else ""
            type_clause = ""
            type_params: list[Any] = []
            if kind in {"secondhand", "rental", "job"}:
                type_clause = "AND type = ?"
                type_params.append(kind)
            params = [like, like, like, like, *type_params]
            if viewer_country:
                params.append(viewer_country)
            rows = list(conn.execute(
                f"""
                SELECT * FROM city_listings
                WHERE deleted_at IS NULL
                  AND status IN ('published', 'reserved')
                  AND (title LIKE ? OR description LIKE ? OR location_text LIKE ? OR category LIKE ?)
                  {type_clause}
                  {country_clause}
                ORDER BY is_promoted DESC, updated_at DESC LIMIT 30
                """,
                params,
            ))
            listings = fetch_listings_with_extras(conn, [dict(r) for r in rows], viewer_id)
        if kind in ("all", "user"):
            country_clause = "AND country = ?" if viewer_country else ""
            params = (like, like, viewer_country) if viewer_country else (like, like)
            rows = list(conn.execute(
                f"SELECT * FROM users WHERE (handle LIKE ? OR display_name LIKE ?) AND deleted_at IS NULL {country_clause} LIMIT 30",
                params,
            ))
            users = [serialize_user(dict(r)) for r in rows]
        if kind in ("all", "topic"):
            country_clause = "AND p.country = ?" if viewer_country else ""
            params = (q.lower().lstrip("#") + "%", viewer_country) if viewer_country else (q.lower().lstrip("#") + "%",)
            rows = list(conn.execute(
                f"""
                SELECT tag, COUNT(*) AS post_count
                FROM post_tags t
                JOIN posts p ON p.id = t.post_id
                WHERE t.tag LIKE ? AND p.deleted_at IS NULL AND p.status IN ('published', 'active')
                  {country_clause}
                GROUP BY tag ORDER BY post_count DESC LIMIT 30
                """,
                params,
            ))
            topics = [{"tag": r["tag"], "post_count": int(r["post_count"])} for r in rows]
        self.send_json({"posts": posts, "listings": listings, "users": users, "topics": topics, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_search_history(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = conn.execute(
            "SELECT DISTINCT query FROM search_history WHERE user_id = ? ORDER BY created_at DESC LIMIT 20",
            (user["id"],),
        )
        self.send_json({"items": [r["query"] for r in rows]})

    def api_clear_search_history(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        conn.execute("DELETE FROM search_history WHERE user_id = ?", (user["id"],))
        self.send_json({"ok": True})

    def api_trending(self, conn: sqlite3.Connection) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        cache_scope = viewer_country or "all"
        # Heavy aggregation — cache per country for 30s so users who
        # registered in Japan only see Japan-side content in global
        # widgets too.
        cached_ids = _cache_get(f"trending:{cache_scope}:post_ids")
        cached_topics = _cache_get(f"trending:{cache_scope}:topics")
        cached_user_ids = _cache_get(f"trending:{cache_scope}:user_ids")
        if cached_ids is None:
            cutoff_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
            country_clause = "AND p.country = ?" if viewer_country else ""
            params: tuple[Any, ...] = (cutoff_24h, viewer_country) if viewer_country else (cutoff_24h,)
            id_rows = list(conn.execute(
                f"""
                SELECT p.id, {_heat_score_sql('p')} AS heat
                FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
                  AND p.created_at >= ?
                  {country_clause}
                ORDER BY heat DESC LIMIT 20
                """,
                params,
            ))
            cached_ids = [r["id"] for r in id_rows]
            _cache_put(f"trending:{cache_scope}:post_ids", cached_ids, ttl_seconds=30)
        if cached_topics is None:
            country_clause = "AND p.country = ?" if viewer_country else ""
            params = (viewer_country,) if viewer_country else ()
            cached_topics = [
                {"tag": r["tag"], "post_count": int(r["c"])}
                for r in conn.execute(
                    f"""
                    SELECT t.tag, COUNT(*) AS c
                    FROM post_tags t
                    JOIN posts p ON p.id = t.post_id
                    WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                      {country_clause}
                    GROUP BY t.tag ORDER BY c DESC LIMIT 20
                    """,
                    params,
                )
            ]
            _cache_put(f"trending:{cache_scope}:topics", cached_topics, ttl_seconds=60)
        if cached_user_ids is None:
            if viewer_country:
                cached_user_ids = [r["id"] for r in conn.execute(
                    "SELECT id FROM users WHERE deleted_at IS NULL AND country = ? ORDER BY is_verified DESC, joined_at LIMIT 12",
                    (viewer_country,),
                )]
            else:
                cached_user_ids = [r["id"] for r in conn.execute(
                    "SELECT id FROM users WHERE deleted_at IS NULL ORDER BY is_verified DESC, joined_at LIMIT 12"
                )]
            _cache_put(f"trending:{cache_scope}:user_ids", cached_user_ids, ttl_seconds=60)
        if cached_ids:
            placeholders = ",".join("?" * len(cached_ids))
            post_rows = list(conn.execute(
                f"SELECT * FROM posts WHERE id IN ({placeholders})", cached_ids,
            ))
            # Preserve heat order.
            order = {pid: i for i, pid in enumerate(cached_ids)}
            post_rows.sort(key=lambda r: order.get(r["id"], 1_000_000))
            posts = fetch_posts_with_extras(conn, [dict(r) for r in post_rows], viewer_id)
        else:
            posts = []
        users: list[dict[str, Any]] = []
        if cached_user_ids:
            placeholders = ",".join("?" * len(cached_user_ids))
            user_rows = list(conn.execute(
                f"SELECT * FROM users WHERE id IN ({placeholders})", cached_user_ids,
            ))
            users = [serialize_user(dict(u)) for u in user_rows]
        self.send_json({
            "posts": posts,
            "topics": cached_topics,
            "users": users,
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_trending_weekly_likes(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        limit = max(1, min(int(query.get("limit") or 10), 30))
        days = max(1, min(int(query.get("days") or 7), 30))
        cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
        # Optional region scoping: region_code wins; else country/province/city;
        # else fall back to the viewer's own country so the list stays local.
        region_code = (query.get("region_code") or query.get("regionCode") or "").strip().lower()
        q_country = (query.get("country") or "").strip().lower()
        q_province = (query.get("province") or "").strip().lower()
        q_city = (query.get("city") or "").strip().lower()
        region_filters: list[str] = []
        region_params: list[Any] = []
        if region_code:
            region_filters.append("p.region_code = ?")
            region_params.append(region_code)
        elif q_country or q_province or q_city:
            if q_country:
                region_filters.append("p.country = ?")
                region_params.append(q_country)
            if q_province:
                region_filters.append("p.province = ?")
                region_params.append(q_province)
            if q_city:
                region_filters.append("p.city = ?")
                region_params.append(q_city)
        elif viewer_country:
            region_filters.append("p.country = ?")
            region_params.append(viewer_country)
        region_clause = ("AND " + " AND ".join(region_filters)) if region_filters else ""
        params: list[Any] = [cutoff, *region_params, limit]
        rows = list(conn.execute(
            f"""
            SELECT p.*, COUNT(*) AS weekly_like_count
            FROM posts p
            JOIN interactions i ON i.target_id = p.id AND i.kind = 'like' AND i.created_at >= ?
            WHERE p.deleted_at IS NULL
              AND p.status IN ('published', 'active')
              {region_clause}
            GROUP BY p.id
            ORDER BY weekly_like_count DESC, p.created_at DESC
            LIMIT ?
            """,
            params,
        ))
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        like_counts = {r["id"]: int(r["weekly_like_count"] or 0) for r in rows}
        for post in posts:
            post["weekly_like_count"] = like_counts.get(post["id"], 0)
            post["weeklyLikes"] = post["weekly_like_count"]
        self.send_json({
            "items": posts,
            "posts": posts,
            "days": days,
            "metric": "weekly_likes",
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_topics(self, conn: sqlite3.Connection) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        country_clause = "AND p.country = ?" if viewer_country else ""
        params: tuple[Any, ...] = (viewer_country,) if viewer_country else ()
        topics = [
            {"tag": r["tag"], "post_count": int(r["c"])}
            for r in conn.execute(
                f"""
                SELECT t.tag, COUNT(*) AS c
                FROM post_tags t
                JOIN posts p ON p.id = t.post_id
                WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                  {country_clause}
                GROUP BY t.tag ORDER BY c DESC LIMIT 50
                """,
                params,
            )
        ]
        self.send_json({
            "topics": topics,
            "items": topics,
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_topic(self, conn: sqlite3.Connection, tag: str, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        tag_clean = tag.lstrip("#").lower()
        sort = query.get("sort") or "latest"
        order = f"{_heat_score_sql('p')} DESC, p.created_at DESC" if sort in ("hot", "high_heat") else "p.created_at DESC"
        rows = list(conn.execute(
            f"""
            SELECT p.* FROM posts p
            JOIN post_tags t ON t.post_id = p.id
            WHERE t.tag = ? AND p.deleted_at IS NULL AND p.status IN ('published', 'active')
            ORDER BY {order} LIMIT 50
            """,
            (tag_clean,),
        ))
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        self.send_json({"tag": tag_clean, "items": posts, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_notifications(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        kind = query.get("kind") or "all"
        clause = ""
        params: list[Any] = [user["id"]]
        if kind != "all":
            clause = " AND type = ?"
            params.append(kind)
        rows = list(conn.execute(
            f"SELECT * FROM notifications WHERE user_id = ? AND deleted_at IS NULL{clause} ORDER BY created_at DESC LIMIT 100",
            params,
        ))
        actor_ids = list({r["actor_id"] for r in rows})
        actor_map = fetch_users_by_ids(conn, actor_ids)
        items = [
            serialize_notification(dict(r), {"actor": actor_map.get(r["actor_id"])})
            for r in rows
        ]
        unread = sum(1 for r in rows if not r["is_read"])
        self.send_json({"items": items, "unread_count": unread})

    def api_mark_notifications(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        if data.get("all"):
            conn.execute("UPDATE notifications SET is_read = 1 WHERE user_id = ?", (user["id"],))
        else:
            ids = data.get("ids") or []
            for nid in ids:
                conn.execute("UPDATE notifications SET is_read = 1 WHERE id = ? AND user_id = ?", (nid, user["id"]))
        self.send_json({"ok": True})

    def api_delete_notification(self, conn: sqlite3.Connection, notif_id: str) -> None:
        user = self.require_user(conn)
        conn.execute(
            "UPDATE notifications SET deleted_at = ? WHERE id = ? AND user_id = ?",
            (now_iso(), notif_id, user["id"]),
        )
        self.send_json({"ok": True})

    def _conversation_for(self, conn: sqlite3.Connection, user_id: str, peer_id: str) -> dict[str, Any]:
        a, b = sorted([user_id, peer_id])
        row = conn.execute(
            "SELECT * FROM conversations WHERE participant_a = ? AND participant_b = ?",
            (a, b),
        ).fetchone()
        if row:
            return dict(row)
        conv_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO conversations (id, participant_a, participant_b, updated_at) VALUES (?, ?, ?, ?)",
            (conv_id, a, b, now_iso()),
        )
        return dict(conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone())

    def api_conversations(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = list(conn.execute(
            "SELECT * FROM conversations WHERE (participant_a = ? OR participant_b = ?) AND deleted_at IS NULL ORDER BY updated_at DESC",
            (user["id"], user["id"]),
        ))
        if not rows:
            self.send_json({"items": []})
            return
        conv_ids = [r["id"] for r in rows]
        placeholders = ",".join("?" * len(conv_ids))
        peer_ids = [
            (r["participant_b"] if r["participant_a"] == user["id"] else r["participant_a"])
            for r in rows
        ]
        users_map = fetch_users_by_ids(conn, peer_ids)
        # Last message per conversation in one pass — grab the latest
        # row per conversation_id using a correlated MAX(rowid).
        last_messages: dict[str, dict[str, Any]] = {}
        for row in conn.execute(
            f"""
            SELECT m.*
            FROM messages m
            JOIN (
              SELECT conversation_id, MAX(rowid) AS max_rowid
              FROM messages
              WHERE deleted_at IS NULL AND conversation_id IN ({placeholders})
              GROUP BY conversation_id
            ) latest
              ON latest.conversation_id = m.conversation_id
              AND latest.max_rowid = m.rowid
            """,
            conv_ids,
        ):
            last_messages[row["conversation_id"]] = dict(row)
        # Unread counts per conversation, single aggregate query.
        unread_map: dict[str, int] = {pid: 0 for pid in conv_ids}
        for row in conn.execute(
            f"""
            SELECT conversation_id, COUNT(*) AS c
            FROM messages
            WHERE deleted_at IS NULL
              AND is_read = 0
              AND sender_id != ?
              AND conversation_id IN ({placeholders})
            GROUP BY conversation_id
            """,
            [user["id"], *conv_ids],
        ):
            unread_map[row["conversation_id"]] = int(row["c"])
        items = []
        for r in rows:
            peer_id = r["participant_b"] if r["participant_a"] == user["id"] else r["participant_a"]
            last = last_messages.get(r["id"])
            items.append(serialize_conversation(dict(r), {
                "peer": users_map.get(peer_id),
                "last_message": serialize_message(last) if last else None,
                "unread_count": unread_map.get(r["id"], 0),
            }))
        self.send_json({"items": items})

    def api_create_conversation(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        peer_id = data.get("peer_id")
        if not peer_id or peer_id == user["id"]:
            raise APIError("无效的对话对象", 400, "invalid_peer")
        peer_row = conn.execute(
            "SELECT * FROM users WHERE (id = ? OR handle = ?) AND deleted_at IS NULL",
            (peer_id, peer_id),
        ).fetchone()
        if not peer_row:
            raise APIError("用户不存在", 404, "user_not_found")
        # The same handle-or-id check above means the lookup might also
        # resolve to the caller via handle. Block it explicitly so we
        # never open a self-DM through the handle path.
        if peer_row["id"] == user["id"]:
            raise APIError("无效的对话对象", 400, "invalid_peer")
        # Respect mutual blocks: neither side can DM if either blocked
        # the other.
        blocked = conn.execute(
            "SELECT 1 FROM blocks WHERE (blocker_id = ? AND blocked_id = ?) OR (blocker_id = ? AND blocked_id = ?)",
            (user["id"], peer_row["id"], peer_row["id"], user["id"]),
        ).fetchone()
        if blocked:
            raise APIError("无法与该用户对话", 403, "blocked")
        rep = reputation_ensure_user(conn, user["id"])
        controls = reputation_effective_limits(conn, rep, user)
        if _clamp_reputation_score(rep.get("reputation_score")) < 20 or _clamp_risk_score(rep.get("risk_score")) >= int(reputation_limit_map(conn).get("restrict_risk_threshold") or 81):
            raise APIError("当前账号信任状态暂不能主动私信陌生人。", 403, "REPUTATION_LIMITED")
        a, b = sorted([user["id"], peer_row["id"]])
        existing_conv = conn.execute(
            "SELECT 1 FROM conversations WHERE participant_a = ? AND participant_b = ? AND deleted_at IS NULL",
            (a, b),
        ).fetchone()
        if not existing_conv:
            since = _reputation_now_window(1)
            today_opened = conn.execute(
                """
                SELECT COUNT(*) AS c
                  FROM conversations
                 WHERE (participant_a = ? OR participant_b = ?)
                   AND updated_at >= ?
                """,
                (user["id"], user["id"], since),
            ).fetchone()["c"]
            if int(today_opened or 0) >= int(controls["dm_daily_limit"] or 0):
                raise APIError("今日主动私信次数已达当前信任额度。", 429, "DM_LIMIT_REACHED")
        conv = self._conversation_for(conn, user["id"], peer_row["id"])
        self.send_json({"conversation": serialize_conversation(conv, {"peer": serialize_user(dict(peer_row))})})

    def api_delete_conversation(self, conn: sqlite3.Connection, conv_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        now = now_iso()
        conn.execute("UPDATE conversations SET deleted_at = ? WHERE id = ?", (now, conv_id))
        conn.execute("UPDATE messages SET deleted_at = ? WHERE conversation_id = ?", (now, conv_id))
        conn.execute(
            "UPDATE message_attachments SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE thread_id = ? AND deleted_at IS NULL",
            (now, now, conv_id),
        )
        self.send_json({"ok": True})

    def api_messages(self, conn: sqlite3.Connection, conv_id: str, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        rows = list(conn.execute(
            "SELECT * FROM messages WHERE conversation_id = ? AND deleted_at IS NULL ORDER BY created_at",
            (conv_id,),
        ))
        message_ids = [r["id"] for r in rows]
        media_by_msg: dict[str, list[dict[str, Any]]] = {}
        if message_ids:
            placeholders = ",".join("?" * len(message_ids))
            for r in conn.execute(
                f"""SELECT mm.message_id, m.* FROM message_media mm
                    JOIN media m ON m.id = mm.media_id
                    WHERE mm.message_id IN ({placeholders}) AND m.deleted_at IS NULL""",
                message_ids,
            ):
                media_by_msg.setdefault(r["message_id"], []).append(serialize_media(dict(r)))
        attachments_by_msg: dict[str, list[dict[str, Any]]] = {}
        if message_ids:
            placeholders = ",".join("?" * len(message_ids))
            for r in conn.execute(
                f"""
                SELECT
                  a.id, a.message_id, a.thread_id, a.uploaded_file_id, a.attachment_type,
                  a.thumbnail_file_id,
                  COALESCE(NULLIF(a.duration_seconds, 0), f.duration, 0) AS duration_seconds,
                  a.file_name,
                  COALESCE(NULLIF(a.file_size, 0), f.file_size, 0) AS file_size,
                  COALESCE(NULLIF(a.content_type, ''), f.content_type, '') AS content_type,
                  a.visibility, a.status, a.created_at,
                  f.file_type, f.width, f.height
                FROM message_attachments a
                JOIN uploaded_files f ON f.id = a.uploaded_file_id
                WHERE a.message_id IN ({placeholders})
                  AND a.deleted_at IS NULL
                  AND a.status != 'deleted'
                  AND f.deleted_at IS NULL
                ORDER BY a.created_at ASC
                """,
                message_ids,
            ):
                item = serialize_message_attachment(dict(r))
                attachments_by_msg.setdefault(item["message_id"], []).append(item)
        items = [
            serialize_message(dict(r), {
                "media": media_by_msg.get(r["id"], []),
                "attachments": attachments_by_msg.get(r["id"], []),
            })
            for r in rows
        ]
        self.send_json({"items": items})

    def api_create_message(self, conn: sqlite3.Connection, conv_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        data = self.read_json()
        content = (data.get("content") or "").strip()
        attachment_ids = list(dict.fromkeys([
            str(v or "").strip()
            for v in (data.get("attachment_ids") or data.get("attachmentIds") or [])
            if str(v or "").strip()
        ]))
        submitted_media_ids = list(dict.fromkeys([
            str(v or "").strip()
            for v in (data.get("media_ids") or data.get("mediaIds") or [])
            if str(v or "").strip()
        ]))
        if not content and not attachment_ids and not submitted_media_ids:
            raise APIError("消息不能为空", 400, "empty_message")
        legacy_media_rows: list[dict[str, Any]] = []
        attachment_rows: list[dict[str, Any]] = []
        attachment_lookup_ids = list(dict.fromkeys([*attachment_ids, *submitted_media_ids]))
        image_count = 0
        video_count = 0
        file_count = 0
        for file_id in attachment_lookup_ids:
            upload_row = conn.execute(
                """
                SELECT * FROM uploaded_files
                 WHERE id = ?
                   AND user_id = ?
                   AND deleted_at IS NULL
                   AND status IN ('uploaded','processing','ready')
                """,
                (file_id, user["id"]),
            ).fetchone()
            if upload_row and str(upload_row["purpose"] or "") in {"message_image", "message_video", "message_file"}:
                upload = dict(upload_row)
                try:
                    metadata = json.loads(upload.get("metadata") or "{}")
                except (TypeError, json.JSONDecodeError):
                    metadata = {}
                if str(metadata.get("thread_id") or metadata.get("threadId") or "") != conv_id:
                    raise APIError("附件不属于该会话", 403, "attachment_thread_mismatch")
                purpose = str(upload.get("purpose") or "")
                attachment_type = "image" if purpose == "message_image" else "video" if purpose == "message_video" else "file"
                if attachment_type == "image":
                    image_count += 1
                    if image_count > 9:
                        raise APIError("每条私信最多发送 9 张图片", 400, "message_image_limit")
                elif attachment_type == "video":
                    video_count += 1
                    if video_count > 1:
                        raise APIError("每条私信最多发送 1 个视频", 400, "message_video_limit")
                else:
                    file_count += 1
                    if file_count > 1:
                        raise APIError("每条私信最多发送 1 个附件文件", 400, "message_file_limit")
                upload["_attachment_type"] = attachment_type
                attachment_rows.append(upload)
                continue
            if file_id in submitted_media_ids:
                media_row = conn.execute(
                    "SELECT * FROM media WHERE id = ? AND owner_id = ? AND deleted_at IS NULL",
                    (file_id, user["id"]),
                ).fetchone()
                if media_row:
                    legacy_media_rows.append(dict(media_row))
                    continue
            raise APIError("包含无权使用的私信附件", 403, "attachment_forbidden")
        message_id = str(uuid.uuid4())
        now = now_iso()
        conn.execute(
            "INSERT INTO messages (id, conversation_id, sender_id, content, created_at, is_read) VALUES (?, ?, ?, ?, ?, 0)",
            (message_id, conv_id, user["id"], content, now),
        )
        for media_row in legacy_media_rows:
            conn.execute("INSERT OR IGNORE INTO message_media VALUES (?, ?)", (message_id, media_row["id"]))
        for upload in attachment_rows:
            attachment_id = "att_" + uuid.uuid4().hex
            conn.execute(
                """
                INSERT INTO message_attachments (
                    id, message_id, thread_id, uploaded_file_id, attachment_type, thumbnail_file_id,
                    duration_seconds, file_name, file_size, content_type, visibility, status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, '', ?, ?, ?, ?, 'thread_members_only', 'ready', ?, ?)
                """,
                (
                    attachment_id, message_id, conv_id, upload["id"], upload["_attachment_type"],
                    float(upload.get("duration") or 0),
                    Path(upload.get("object_key") or "").name,
                    int(upload.get("file_size") or 0),
                    upload.get("content_type") or "",
                    now, now,
                ),
            )
            conn.execute(
                "UPDATE uploaded_files SET entity_type = 'message', entity_id = ?, updated_at = ? WHERE id = ?",
                (message_id, now, upload["id"]),
            )
            record_upload_audit(conn, user["id"], "message_attachment_link", file_id=upload["id"], status="ready", metadata={"messageId": message_id, "threadId": conv_id, "attachmentId": attachment_id})
        conn.execute("UPDATE conversations SET updated_at = ? WHERE id = ?", (now, conv_id))
        peer_id = row["participant_b"] if row["participant_a"] == user["id"] else row["participant_a"]
        HUB.publish(peer_id, {"type": "message", "conversation_id": conv_id, "message_id": message_id})
        fresh = dict(conn.execute("SELECT * FROM messages WHERE id = ?", (message_id,)).fetchone())
        media_rows = [serialize_media(dict(r)) for r in conn.execute(
            "SELECT m.* FROM message_media mm JOIN media m ON m.id = mm.media_id WHERE mm.message_id = ?",
            (message_id,),
        )]
        attachment_items = [
            serialize_message_attachment(dict(r))
            for r in conn.execute(
                """
                SELECT
                  a.id, a.message_id, a.thread_id, a.uploaded_file_id, a.attachment_type,
                  a.thumbnail_file_id,
                  COALESCE(NULLIF(a.duration_seconds, 0), f.duration, 0) AS duration_seconds,
                  a.file_name,
                  COALESCE(NULLIF(a.file_size, 0), f.file_size, 0) AS file_size,
                  COALESCE(NULLIF(a.content_type, ''), f.content_type, '') AS content_type,
                  a.visibility, a.status, a.created_at,
                  f.file_type, f.width, f.height
                FROM message_attachments a
                JOIN uploaded_files f ON f.id = a.uploaded_file_id
                WHERE a.message_id = ?
                  AND a.deleted_at IS NULL
                  AND a.status != 'deleted'
                  AND f.deleted_at IS NULL
                ORDER BY a.created_at ASC
                """,
                (message_id,),
            )
        ]
        self.send_json({"message": serialize_message(fresh, {"media": media_rows, "attachments": attachment_items})})

    def api_delete_message(self, conn: sqlite3.Connection, msg_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM messages WHERE id = ?", (msg_id,)).fetchone()
        if not row or row["sender_id"] != user["id"]:
            raise APIError("无权操作", 403, "forbidden")
        now = now_iso()
        conn.execute("UPDATE messages SET deleted_at = ? WHERE id = ?", (now, msg_id))
        conn.execute(
            "UPDATE message_attachments SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE message_id = ? AND deleted_at IS NULL",
            (now, now, msg_id),
        )
        self.send_json({"ok": True})

    def api_message_attachment_view_url(self, conn: sqlite3.Connection, msg_id: str, attachment_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute(
            """
            SELECT
              a.id AS attachment_id,
              a.message_id,
              a.thread_id,
              a.uploaded_file_id,
              a.status AS attachment_status,
              f.id AS file_id,
              f.user_id AS file_owner_id,
              f.bucket,
              f.object_key,
              f.content_type,
              f.status AS file_status,
              f.purpose,
              c.participant_a,
              c.participant_b
            FROM message_attachments a
            JOIN messages m ON m.id = a.message_id AND m.deleted_at IS NULL
            JOIN conversations c ON c.id = m.conversation_id AND c.deleted_at IS NULL
            JOIN uploaded_files f ON f.id = a.uploaded_file_id
            WHERE a.id = ?
              AND a.message_id = ?
              AND a.deleted_at IS NULL
              AND a.status != 'deleted'
              AND f.deleted_at IS NULL
              AND f.status != 'deleted'
            LIMIT 1
            """,
            (attachment_id, msg_id),
        ).fetchone()
        if not row:
            raise APIError("附件不存在", 404, "attachment_not_found")
        d = dict(row)
        if d["participant_a"] != user["id"] and d["participant_b"] != user["id"] and user.get("role") != "admin":
            record_upload_audit(conn, user["id"], "message_attachment_view_denied", file_id=d["file_id"], status="failed", reason="thread_forbidden", metadata={"messageId": msg_id, "attachmentId": attachment_id})
            raise APIError("无权查看该附件", 403, "forbidden")
        if str(d.get("purpose") or "") not in {"message_image", "message_video", "message_file"}:
            raise APIError("附件类型不支持", 400, "invalid_attachment_purpose")
        if str(d.get("file_status") or "") not in {"uploaded", "processing", "ready"}:
            raise APIError("附件尚未可用", 409, "attachment_not_ready")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        if d.get("bucket") != "local-dev":
            url = _s3_presigned_url("GET", d["object_key"], expires=expires)
        else:
            exp = int(time.time()) + expires
            token = _signed_local_download_token(d["file_id"], exp)
            base = self._request_base_url()
            path = f"/api/uploads/download/{d['file_id']}?token={token}"
            url = f"{base}{path}" if base else path
        record_upload_audit(conn, user["id"], "message_attachment_view_url", file_id=d["file_id"], status="ready", metadata={"messageId": msg_id, "threadId": d["thread_id"], "attachmentId": attachment_id, "expires": expires})
        self.send_json({"ok": True, "data": {"url": url, "expiresIn": expires}, "url": url, "expiresIn": expires})

    def api_mark_conversation_read(self, conn: sqlite3.Connection, conv_id: str) -> None:
        user = self.require_user(conn)
        conn.execute(
            "UPDATE messages SET is_read = 1 WHERE conversation_id = ? AND sender_id != ?",
            (conv_id, user["id"]),
        )
        self.send_json({"ok": True})

    # ---- S3 / unified uploads ----

    def _assert_upload_entity_permission(
        self,
        conn: sqlite3.Connection,
        user: dict[str, Any],
        *,
        purpose: str,
        entity_type: str,
        entity_id: str,
    ) -> None:
        spec = UPLOAD_PURPOSES[purpose]
        if spec.get("admin") and user.get("role") != "admin":
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="admin_required", metadata={"purpose": purpose})
            raise APIError("该文件只能由管理员上传", 403, "admin_required")
        if purpose == "business_verification_file" and user.get("role") != "admin":
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="admin_required", metadata={"purpose": purpose})
            raise APIError("认证材料附件只能由后台上传", 403, "admin_required")
        rep = reputation_ensure_user(conn, user["id"])
        if int(rep.get("risk_score") or 0) >= 80:
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="high_risk_user", metadata={"purpose": purpose})
            raise APIError("账号风险过高，暂不能上传文件", 403, "upload_restricted")
        if entity_type == "post" and entity_id:
            row = conn.execute("SELECT author_id FROM posts WHERE id = ? AND deleted_at IS NULL", (entity_id,)).fetchone()
            if not row or row["author_id"] != user["id"]:
                raise APIError("无权给该帖子上传文件", 403, "forbidden")
        elif entity_type == "listing" and entity_id:
            row = conn.execute("SELECT seller_user_id FROM city_listings WHERE id = ? AND deleted_at IS NULL", (entity_id,)).fetchone()
            if not row or row["seller_user_id"] != user["id"]:
                raise APIError("无权给该信息上传文件", 403, "forbidden")
        elif entity_type == "business" and entity_id and user.get("role") != "admin":
            row = conn.execute("SELECT owner_user_id FROM business_profiles WHERE id = ?", (entity_id,)).fetchone()
            if not row or row["owner_user_id"] != user["id"]:
                raise APIError("无权给该商家上传文件", 403, "forbidden")
        elif entity_type in {"guide_article", "guide_product"} and entity_id and user.get("role") != "admin":
            raise APIError("Guide 文件只能由管理员上传", 403, "admin_required")

    def _check_upload_quota(
        self,
        conn: sqlite3.Connection,
        user_id: str,
        *,
        purpose: str,
        entity_type: str,
        entity_id: str,
    ) -> None:
        since = (datetime.now(timezone.utc) - timedelta(days=1)).isoformat()
        daily = conn.execute(
            "SELECT COUNT(*) AS c FROM uploaded_files WHERE user_id = ? AND created_at >= ? AND deleted_at IS NULL",
            (user_id, since),
        ).fetchone()["c"]
        if int(daily or 0) >= 120:
            raise APIError("今日上传次数已达上限", 429, "daily_upload_limit")
        limit = int(UPLOAD_PURPOSES[purpose].get("count") or 0)
        if limit <= 0 or purpose in {"avatar", "profile_cover", "business_logo", "business_cover"}:
            return
        if not (entity_type and entity_id):
            return
        count = conn.execute(
            """
            SELECT COUNT(*) AS c FROM uploaded_files
             WHERE user_id = ? AND purpose = ? AND entity_type = ? AND entity_id = ?
               AND status NOT IN ('deleted','failed') AND deleted_at IS NULL
            """,
            (user_id, purpose, entity_type, entity_id),
        ).fetchone()["c"]
        if int(count or 0) >= limit:
            raise APIError("该内容的上传数量已达上限", 400, "upload_count_limit")

    def api_upload_presign(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        purpose = normalize_upload_purpose(data.get("purpose"))
        content_type = canonical_upload_mime(purpose, str(data.get("contentType") or data.get("content_type") or ""))
        try:
            file_size = int(data.get("fileSize") or data.get("file_size") or 0)
        except (TypeError, ValueError):
            raise APIError("文件大小不合法", 400, "invalid_file_size")
        if file_size <= 0:
            raise APIError("文件大小不能为空", 400, "invalid_file_size")
        max_bytes = min(int(UPLOAD_PURPOSES[purpose]["max"]), S3_UPLOAD_MAX_SIZE)
        if file_size > max_bytes:
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="file_too_large", metadata={"purpose": purpose, "fileSize": file_size})
            raise APIError("文件太大", 413, "file_too_large")
        entity_type = normalize_upload_entity_type(data.get("entityType") or data.get("entity_type"))
        entity_id = str(data.get("entityId") or data.get("entity_id") or "").strip()
        thread_id = str(data.get("threadId") or data.get("thread_id") or data.get("conversationId") or data.get("conversation_id") or "").strip()
        group_id = str(data.get("groupId") or data.get("group_id") or "").strip()
        raw_metadata = data.get("metadata") if isinstance(data.get("metadata"), dict) else {}
        duration_seconds = max(0.0, float(raw_metadata.get("durationSeconds") or raw_metadata.get("duration_seconds") or data.get("duration") or data.get("durationSeconds") or 0))
        max_duration_by_purpose = {
            "post_video": 5 * 60,
            "article_video": 10 * 60,
            "experience_video": 5 * 60,
            "group_post_video": 5 * 60,
            "message_video": 2 * 60,
        }
        if purpose in max_duration_by_purpose and duration_seconds > max_duration_by_purpose[purpose]:
            raise APIError("视频时长超过限制", 400, "video_duration_too_long")
        if purpose in {"message_image", "message_video", "message_file"}:
            if not thread_id:
                raise APIError("私信上传需要 threadId", 400, "missing_thread_id")
            thread = conn.execute("SELECT * FROM conversations WHERE id = ? AND deleted_at IS NULL", (thread_id,)).fetchone()
            if not thread or (thread["participant_a"] != user["id"] and thread["participant_b"] != user["id"]):
                record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="thread_forbidden", metadata={"purpose": purpose, "threadId": thread_id})
                raise APIError("无权在该会话上传附件", 403, "thread_forbidden")
            entity_type = "message"
        self._assert_upload_entity_permission(conn, user, purpose=purpose, entity_type=entity_type, entity_id=entity_id)
        self._check_upload_quota(conn, user["id"], purpose=purpose, entity_type=entity_type, entity_id=entity_id)

        upload_id = "upload_" + uuid.uuid4().hex
        file_id = "file_" + uuid.uuid4().hex
        object_key = upload_object_key(user["id"], purpose, entity_type, entity_id, content_type, thread_id=thread_id, group_id=group_id)
        is_private = upload_is_private(purpose)
        cdn_url = upload_public_url(object_key, purpose)
        use_s3 = s3_ready_for_upload()
        if use_s3:
            try:
                upload_url = _s3_presigned_url("PUT", object_key, content_type=content_type, expires=S3_PRESIGN_EXPIRES_SECONDS)
            except APIError:
                if PRODUCTION:
                    record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="s3_presign_failed", metadata={"purpose": purpose})
                    raise
                use_s3 = False
        if not use_s3:
            token = _local_upload_token(upload_id, user["id"], object_key)
            base = self._request_base_url()
            path = f"/api/uploads/local/{upload_id}?token={quote(token, safe='')}"
            upload_url = f"{base}{path}" if base else path
        bucket = AWS_S3_BUCKET if use_s3 else "local-dev"
        metadata = {
            "source": "s3" if use_s3 else "local",
            "thumbnail_url": upload_thumbnail_url(object_key, content_type, purpose),
            "thread_id": thread_id,
            "group_id": group_id,
            "duration_seconds": duration_seconds,
            "moderation_status": "needs_review" if purpose.endswith("_video") else "clear",
            "processing_status": "pending" if purpose.endswith("_video") else "ready",
            "variants": {} if is_private else {
                "original": cdn_url,
                "large": cdn_url,
                "medium": cdn_url,
                "thumbnail": upload_thumbnail_url(object_key, content_type, purpose) or cdn_url,
            },
        }
        now = now_iso()
        conn.execute(
            """
            INSERT INTO uploaded_files (
                id, upload_id, user_id, bucket, object_key, public_url, cdn_url, content_type,
                file_size, file_type, purpose, entity_type, entity_id, status, metadata, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?)
            """,
            (
                file_id, upload_id, user["id"], bucket, object_key, cdn_url, cdn_url, content_type,
                file_size, upload_file_type(content_type), purpose, entity_type, entity_id,
                json.dumps(metadata, ensure_ascii=False, sort_keys=True), now, now,
            ),
        )
        record_upload_audit(conn, user["id"], "presign", file_id=file_id, upload_id=upload_id, status="pending", metadata={"purpose": purpose, "entityType": entity_type, "entityId": entity_id, "s3": use_s3})
        self.send_json({
            "ok": True,
            "data": {
                "uploadId": upload_id,
                "uploadUrl": upload_url,
                "fileKey": object_key,
                "bucket": bucket,
                "publicUrl": cdn_url or None,
                "cdnUrl": cdn_url,
                "expiresIn": S3_PRESIGN_EXPIRES_SECONDS,
                "headers": {"Content-Type": content_type},
                "file": serialize_uploaded_file(conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (file_id,)).fetchone()),
            },
        })

    def api_upload_local_put(self, conn: sqlite3.Connection, upload_id: str, query: dict[str, str]) -> None:
        row = conn.execute("SELECT * FROM uploaded_files WHERE upload_id = ? AND deleted_at IS NULL", (upload_id,)).fetchone()
        if not row:
            raise APIError("上传不存在", 404, "upload_not_found")
        d = dict(row)
        expected_token = _local_upload_token(upload_id, d.get("user_id") or "", d.get("object_key") or "")
        if not expected_token or not hmac.compare_digest(expected_token, query.get("token") or ""):
            raise APIError("上传地址已失效", 403, "invalid_upload_token")
        if d.get("status") not in {"pending", "failed"}:
            raise APIError("上传状态不允许覆盖", 409, "invalid_upload_state")
        length = int(self.headers.get("Content-Length", 0) or 0)
        if length <= 0:
            raise APIError("empty upload", 400, "invalid_payload")
        if length > int(d["file_size"] or 0) or length > min(S3_UPLOAD_MAX_SIZE, int(UPLOAD_PURPOSES[d["purpose"]]["max"])):
            conn.execute("UPDATE uploaded_files SET status = 'failed', updated_at = ? WHERE id = ?", (now_iso(), d["id"]))
            record_upload_audit(conn, d["user_id"], "put_failed", file_id=d["id"], upload_id=upload_id, status="failed", reason="file_too_large")
            raise APIError("文件太大", 413, "file_too_large")
        with _DBLockReleased():
            raw = self.rfile.read(length)
            sniffed = _sniff_mime(raw)
            if not upload_mime_matches(sniffed, d["content_type"]):
                raise APIError("文件类型与签名不一致", 415, "mime_mismatch")
            target = local_upload_path(d["object_key"])
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_bytes(raw)
        etag = hashlib.md5(raw).hexdigest()
        conn.execute(
            "UPDATE uploaded_files SET status = 'uploaded', checksum = ?, etag = ?, updated_at = ? WHERE id = ?",
            (hashlib.sha256(raw).hexdigest(), etag, now_iso(), d["id"]),
        )
        record_upload_audit(conn, d["user_id"], "put", file_id=d["id"], upload_id=upload_id, status="uploaded", metadata={"bytes": length})
        self.send_empty(200, {"ETag": etag})

    def api_upload_complete(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        upload_id = str(data.get("uploadId") or data.get("upload_id") or "").strip()
        file_key = str(data.get("fileKey") or data.get("file_key") or "").strip()
        row = conn.execute(
            "SELECT * FROM uploaded_files WHERE upload_id = ? AND user_id = ? AND deleted_at IS NULL",
            (upload_id, user["id"]),
        ).fetchone()
        if not row:
            raise APIError("上传不存在", 404, "upload_not_found")
        d = dict(row)
        if file_key and file_key != d["object_key"]:
            raise APIError("fileKey 不匹配", 400, "file_key_mismatch")
        if d["status"] not in {"pending", "uploaded", "processing", "ready", "failed"}:
            raise APIError("上传状态不正确", 409, "invalid_upload_state")
        head: dict[str, Any] = {}
        if d.get("bucket") != "local-dev":
            try:
                head = _s3_head_object(d["object_key"])
            except APIError as exc:
                record_upload_audit(conn, user["id"], "complete_failed", file_id=d["id"], upload_id=upload_id, status="failed", reason=exc.code, metadata={"objectKey": d["object_key"]})
                raise
            content_length = int(head.get("ContentLength") or 0)
            if content_length <= 0:
                raise APIError("S3 文件为空", 400, "s3_object_empty")
            if content_length > int(d["file_size"] or 0):
                raise APIError("S3 文件大小与签名不匹配", 400, "s3_size_mismatch")
        elif not local_upload_path(d["object_key"]).exists():
            raise APIError("文件尚未上传完成", 400, "upload_not_found")
        width = max(0, int(data.get("width") or 0))
        height = max(0, int(data.get("height") or 0))
        duration = max(0.0, float(data.get("duration") or 0))
        etag = str(data.get("etag") or head.get("ETag") or d.get("etag") or "").strip().strip('"')
        metadata = json.loads(d.get("metadata") or "{}")
        metadata["thumbnail_url"] = metadata.get("thumbnail_url") or upload_thumbnail_url(d["object_key"], d["content_type"], d["purpose"])
        metadata["completed_at"] = now_iso()
        if head:
            metadata["s3_head_checked_at"] = metadata["completed_at"]
        conn.execute(
            """
            UPDATE uploaded_files
               SET status = 'ready', width = ?, height = ?, duration = ?, etag = ?, metadata = ?, updated_at = ?
             WHERE id = ?
            """,
            (width, height, duration, etag, json.dumps(metadata, ensure_ascii=False, sort_keys=True), now_iso(), d["id"]),
        )
        fresh = dict(conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (d["id"],)).fetchone())
        media = uploaded_file_as_media(fresh)
        conn.execute(
            """
            INSERT INTO media (id, owner_id, type, url, thumb_url, mime, width, height, duration, byte_size, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
                url = excluded.url,
                thumb_url = excluded.thumb_url,
                mime = excluded.mime,
                width = excluded.width,
                height = excluded.height,
                duration = excluded.duration,
                byte_size = excluded.byte_size,
                deleted_at = NULL
            """,
            (
                media["id"], media["owner_id"], media["type"], media["url"], media["thumb_url"],
                media["mime"], media["width"], media["height"], media["duration"], media["byte_size"], media["created_at"],
            ),
        )
        if fresh["purpose"] in {"avatar", "profile_cover"}:
            field = "avatar_url" if fresh["purpose"] == "avatar" else "cover_url"
            conn.execute(f"UPDATE users SET {field} = ?, updated_at = ? WHERE id = ?", (media["url"], now_iso(), user["id"]))
        record_upload_audit(conn, user["id"], "complete", file_id=fresh["id"], upload_id=upload_id, status="ready")
        self.send_json({"ok": True, "data": {"file": serialize_uploaded_file(fresh), "media": media}, "file": serialize_uploaded_file(fresh), "media": media})

    def _uploaded_file_for_user(self, conn: sqlite3.Connection, file_id: str, user: dict[str, Any]) -> dict[str, Any]:
        row = conn.execute("SELECT * FROM uploaded_files WHERE id = ? AND deleted_at IS NULL", (file_id,)).fetchone()
        if not row:
            raise APIError("文件不存在", 404, "file_not_found")
        d = dict(row)
        if d["user_id"] != user["id"] and user.get("role") != "admin":
            raise APIError("无权操作", 403, "forbidden")
        return d

    def api_upload_get(self, conn: sqlite3.Connection, file_id: str) -> None:
        user = self.require_user(conn)
        d = self._uploaded_file_for_user(conn, file_id, user)
        self.send_json({"ok": True, "data": {"file": serialize_uploaded_file(d)}, "file": serialize_uploaded_file(d)})

    def api_upload_delete(self, conn: sqlite3.Connection, file_id: str) -> None:
        user = self.require_user(conn)
        d = self._uploaded_file_for_user(conn, file_id, user)
        linked = conn.execute(
            """
            SELECT
              (SELECT COUNT(*) FROM post_media WHERE media_id = ?) +
              (SELECT COUNT(*) FROM message_media WHERE media_id = ?) +
              (SELECT COUNT(*) FROM message_attachments WHERE uploaded_file_id = ? AND deleted_at IS NULL) +
              (SELECT COUNT(*) FROM listing_media WHERE uploaded_file_id = ? OR id = ?) AS c
            """,
            (file_id, file_id, file_id, file_id, file_id),
        ).fetchone()["c"]
        if int(linked or 0) > 0 and user.get("role") != "admin":
            raise APIError("文件已被内容使用，请先解除关联", 409, "file_in_use")
        now = now_iso()
        conn.execute("UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?", (now, now, file_id))
        conn.execute("UPDATE media SET deleted_at = ? WHERE id = ?", (now, file_id))
        record_upload_audit(conn, user["id"], "delete_mark", file_id=file_id, status="deleted")
        self.send_json({"ok": True, "status": "deleted"})

    def api_admin_uploads(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 100), 300))
        status = (query.get("status") or "").strip()
        purpose = (query.get("purpose") or "").strip()
        user_id = (query.get("userId") or query.get("user_id") or "").strip()
        q = (query.get("q") or "").strip()
        incomplete = (query.get("incomplete") or "").strip().lower() in {"1", "true", "yes"}
        large = (query.get("large") or "").strip().lower() in {"1", "true", "yes"}
        check_object = (query.get("checkObject") or query.get("check_object") or "").strip().lower() in {"1", "true", "yes"}
        clauses = ["1 = 1"]
        params: list[Any] = []
        if status:
            clauses.append("f.status = ?")
            params.append(status)
        if purpose:
            clauses.append("f.purpose = ?")
            params.append(purpose)
        if user_id:
            clauses.append("f.user_id = ?")
            params.append(user_id)
        if incomplete:
            clauses.append("f.status IN ('pending','uploaded','processing','failed')")
        if large:
            clauses.append("f.file_size >= ?")
            params.append(10 * 1024 * 1024)
        if q:
            like = f"%{q}%"
            clauses.append("(f.id LIKE ? OR f.upload_id LIKE ? OR f.object_key LIKE ? OR u.handle LIKE ? OR u.display_name LIKE ?)")
            params.extend([like, like, like, like, like])
        where_sql = " AND ".join(clauses)
        rows = conn.execute(
            f"""
            SELECT f.*, u.handle AS owner_handle, u.display_name AS owner_name
              FROM uploaded_files f
              LEFT JOIN users u ON u.id = f.user_id
             WHERE {where_sql}
             ORDER BY f.created_at DESC
             LIMIT ?
            """,
            [*params, limit],
        ).fetchall()
        total = conn.execute(
            f"SELECT COUNT(*) AS c FROM uploaded_files f LEFT JOIN users u ON u.id = f.user_id WHERE {where_sql}",
            params,
        ).fetchone()["c"]
        items = []
        for row in rows:
            item = serialize_uploaded_file(row)
            item["ownerHandle"] = row["owner_handle"] or ""
            item["ownerName"] = row["owner_name"] or ""
            if check_object:
                if row["bucket"] == "local-dev":
                    item["objectExists"] = local_upload_path(row["object_key"]).exists()
                elif row["status"] not in {"pending", "deleted"}:
                    try:
                        _s3_head_object(row["object_key"])
                        item["objectExists"] = True
                    except APIError:
                        item["objectExists"] = False
            items.append(item)
        self.send_json({"ok": True, "items": items, "total": int(total or 0)})

    def api_admin_update_upload(self, conn: sqlite3.Connection, file_id: str) -> None:
        admin = self.require_admin(conn)
        row = conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (file_id,)).fetchone()
        if not row:
            raise APIError("文件不存在", 404, "file_not_found")
        data = self.read_json()
        updates: dict[str, Any] = {}
        try:
            current_metadata = json.loads(row["metadata"] or "{}")
        except json.JSONDecodeError:
            current_metadata = {}
        metadata = dict(current_metadata)
        action = str(data.get("action") or "").strip()
        if action == "restore":
            updates["status"] = "ready"
            updates["deleted_at"] = ""
            metadata["restored_at"] = now_iso()
        elif action in {"flag", "mark_abnormal"}:
            updates["status"] = "failed"
            metadata["flagged"] = True
            metadata["flag_reason"] = str(data.get("reason") or "admin_flagged")[:240]
            metadata["flagged_at"] = now_iso()
        if "status" in data:
            status = str(data.get("status") or "").strip()
            if status not in {"pending", "uploaded", "processing", "ready", "failed", "deleted"}:
                raise APIError("状态不合法", 400, "invalid_status")
            updates["status"] = status
            if status == "deleted":
                updates["deleted_at"] = now_iso()
            else:
                updates["deleted_at"] = ""
        if "metadata" in data and isinstance(data["metadata"], dict):
            metadata.update(data["metadata"])
        if metadata != current_metadata:
            updates["metadata"] = json.dumps(metadata, ensure_ascii=False, sort_keys=True)
        if not updates:
            return self.send_json({"ok": True, "file": serialize_uploaded_file(row)})
        updates["updated_at"] = now_iso()
        cols = ", ".join(f"{col} = ?" for col in updates)
        conn.execute(f"UPDATE uploaded_files SET {cols} WHERE id = ?", [*updates.values(), file_id])
        fresh = conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (file_id,)).fetchone()
        record_upload_audit(conn, admin["id"], "admin_update", file_id=file_id, status=updates.get("status", ""), metadata={"fields": list(updates.keys())})
        self.send_json({"ok": True, "file": serialize_uploaded_file(fresh)})

    def api_admin_cleanup_temp_uploads(self, conn: sqlite3.Connection) -> None:
        admin = self.require_admin(conn)
        data = self.read_json()
        hours = max(1, min(int(data.get("hours") or 24), 720))
        hard_delete = bool(data.get("hardDelete"))
        cutoff = (datetime.now(timezone.utc) - timedelta(hours=hours)).isoformat()
        rows = conn.execute(
            """
            SELECT * FROM uploaded_files
             WHERE deleted_at IS NULL
               AND created_at < ?
               AND (status IN ('pending','failed') OR object_key LIKE 'temp/%')
             ORDER BY created_at ASC
             LIMIT 500
            """,
            (cutoff,),
        ).fetchall()
        now = now_iso()
        deleted_objects = 0
        for row in rows:
            d = dict(row)
            conn.execute(
                "UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?",
                (now, now, d["id"]),
            )
            if hard_delete and (d.get("object_key") or "").startswith("temp/"):
                if d.get("bucket") == "local-dev":
                    target = local_upload_path(d["object_key"])
                    if target.exists() and target.is_file():
                        try:
                            target.unlink()
                            deleted_objects += 1
                        except OSError:
                            pass
                elif _s3_delete_object(d["object_key"]):
                    deleted_objects += 1
            record_upload_audit(conn, admin["id"], "temp_cleanup", file_id=d["id"], upload_id=d.get("upload_id") or "", status="deleted", metadata={"hours": hours, "hardDelete": hard_delete})
        record_admin_action(conn, admin["id"], "uploads_cleanup_temp", target_kind="uploaded_files", target_id="bulk", metadata={"count": len(rows), "deletedObjects": deleted_objects, "hours": hours, "hardDelete": hard_delete})
        self.send_json({"ok": True, "count": len(rows), "deletedObjects": deleted_objects})

    def api_admin_delete_upload(self, conn: sqlite3.Connection, file_id: str) -> None:
        admin = self.require_admin(conn)
        if not conn.execute("SELECT id FROM uploaded_files WHERE id = ?", (file_id,)).fetchone():
            raise APIError("文件不存在", 404, "file_not_found")
        now = now_iso()
        conn.execute("UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?", (now, now, file_id))
        conn.execute("UPDATE media SET deleted_at = ? WHERE id = ?", (now, file_id))
        record_upload_audit(conn, admin["id"], "admin_delete_mark", file_id=file_id, status="deleted")
        self.send_json({"ok": True, "status": "deleted"})

    def _find_uploaded_file_by_url_or_id(self, conn: sqlite3.Connection, value: str) -> dict[str, Any] | None:
        raw = (value or "").strip()
        if not raw:
            return None
        row = conn.execute(
            """
            SELECT * FROM uploaded_files
             WHERE (id = ? OR cdn_url = ? OR public_url = ? OR object_key = ?)
               AND deleted_at IS NULL
               AND status IN ('uploaded','processing','ready')
             ORDER BY created_at DESC LIMIT 1
            """,
            (raw, raw, raw, raw.removeprefix("/media/")),
        ).fetchone()
        return dict(row) if row else None

    def api_guide_product_download_url(self, conn: sqlite3.Connection, product_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM guide_products WHERE id = ? OR slug = ? LIMIT 1", (product_id, product_id)).fetchone()
        if not row:
            raise APIError("资料/服务不存在", 404, "guide_product_not_found")
        if row["status"] != "published" or bool(row["is_coming_soon"]):
            raise APIError("资料尚未发布", 404, "guide_product_not_available")
        if bool(row["is_service"]) or not bool(row["is_digital"]):
            raise APIError("该项目不是可下载资料", 400, "guide_product_not_downloadable")
        owned = conn.execute(
            "SELECT 1 FROM guide_orders WHERE user_id = ? AND product_id = ? AND status IN ('paid','fulfilled') LIMIT 1",
            (user["id"], row["id"]),
        ).fetchone() is not None
        member_unlocked = bool(row["is_member_included"]) and not bool(row["is_service"]) and has_active_membership(conn, user["id"])
        if not (owned or member_unlocked or bool(row["is_free"])):
            record_upload_audit(conn, user["id"], "download_denied", status="failed", reason="not_entitled", metadata={"productId": row["id"]})
            raise APIError("未解锁该资料", 403, "not_entitled")
        file_ref = row["file_url"] or ""
        upload = self._find_uploaded_file_by_url_or_id(conn, file_ref)
        if not upload:
            files = conn.execute(
                """
                SELECT f.* FROM guide_product_files g
                JOIN uploaded_files f ON f.id = g.uploaded_file_id
                WHERE g.product_id = ?
                  AND f.deleted_at IS NULL
                  AND f.status IN ('uploaded','processing','ready')
                ORDER BY g.created_at DESC LIMIT 1
                """,
                (row["id"],),
            ).fetchone()
            upload = dict(files) if files else None
        if not upload:
            raise APIError("资料文件尚未配置", 404, "guide_file_not_found")
        if str(upload.get("purpose") or "") not in {"guide_product_file", "member_resource_file"}:
            raise APIError("资料文件类型不正确", 400, "invalid_guide_file")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        if upload.get("bucket") != "local-dev":
            url = _s3_presigned_url("GET", upload["object_key"], expires=expires)
        else:
            exp = int(time.time()) + expires
            token = _signed_local_download_token(upload["id"], exp)
            base = self._request_base_url()
            path = f"/api/uploads/download/{upload['id']}?token={token}"
            url = f"{base}{path}" if base else path
        record_upload_audit(conn, user["id"], "download_url", file_id=upload["id"], status="ready", metadata={"productId": row["id"], "expires": expires})
        self.send_json({"ok": True, "downloadUrl": url, "expiresIn": expires, "file": serialize_uploaded_file(upload)})

    def api_member_resource_download_url(self, conn: sqlite3.Connection, resource_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute(
            """
            SELECT * FROM guide_products
             WHERE (id = ? OR slug = ?)
               AND is_member_included = 1
               AND is_service = 0
               AND status = 'published'
             LIMIT 1
            """,
            (resource_id, resource_id),
        ).fetchone()
        if not row:
            raise APIError("会员资料不存在", 404, "member_resource_not_found")
        if not has_active_membership(conn, user["id"]):
            record_upload_audit(conn, user["id"], "member_download_denied", status="failed", reason="membership_required", metadata={"resourceId": row["id"]})
            raise APIError("下载会员资料需要有效会员", 403, "MEMBERSHIP_REQUIRED")
        upload = self._find_uploaded_file_by_url_or_id(conn, row["file_url"] or "")
        if not upload:
            files = conn.execute(
                """
                SELECT f.* FROM guide_product_files g
                JOIN uploaded_files f ON f.id = g.uploaded_file_id
                WHERE g.product_id = ?
                  AND f.deleted_at IS NULL
                  AND f.status IN ('uploaded','processing','ready')
                ORDER BY g.created_at DESC LIMIT 1
                """,
                (row["id"],),
            ).fetchone()
            upload = dict(files) if files else None
        if not upload:
            raise APIError("会员资料文件尚未配置", 404, "member_resource_file_not_found")
        if str(upload.get("purpose") or "") != "member_resource_file":
            raise APIError("会员资料文件类型不正确", 400, "invalid_member_resource_file")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        if upload.get("bucket") != "local-dev":
            url = _s3_presigned_url("GET", upload["object_key"], expires=expires)
        else:
            exp = int(time.time()) + expires
            token = _signed_local_download_token(upload["id"], exp)
            base = self._request_base_url()
            path = f"/api/uploads/download/{upload['id']}?token={token}"
            url = f"{base}{path}" if base else path
        record_upload_audit(conn, user["id"], "member_download_url", file_id=upload["id"], status="ready", metadata={"resourceId": row["id"], "expires": expires})
        self.send_json({"ok": True, "downloadUrl": url, "expiresIn": expires, "file": serialize_uploaded_file(upload)})

    def api_upload_signed_download(self, conn: sqlite3.Connection, file_id: str, query: dict[str, str]) -> None:
        if not _verify_local_download_token(file_id, query.get("token") or ""):
            raise APIError("下载链接已失效", 403, "invalid_download_token")
        row = conn.execute(
            "SELECT * FROM uploaded_files WHERE id = ? AND status IN ('uploaded','processing','ready') AND deleted_at IS NULL",
            (file_id,),
        ).fetchone()
        if not row:
            raise APIError("文件不存在", 404, "file_not_found")
        d = dict(row)
        target = local_upload_path(d["object_key"])
        if not target.exists() or target.is_dir():
            raise APIError("文件不存在", 404, "file_not_found")
        data = target.read_bytes()
        self.send_response(200)
        self.send_header("Content-Type", d["content_type"] or "application/octet-stream")
        self.send_header("Content-Length", str(len(data)))
        self.send_header("Cache-Control", "private, max-age=60")
        self.send_header("Content-Disposition", f'attachment; filename="{Path(d["object_key"]).name}"')
        self._set_cors()
        self._set_security_headers()
        self.end_headers()
        self.wfile.write(data)

    def api_upload_media(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        ctype = self.headers.get("Content-Type", "")
        if "multipart/form-data" in ctype:
            self._upload_multipart(conn, user)
            return
        data = self.read_json()
        base64_payload = data.get("data") or ""
        declared_mime = (data.get("mime") or "").lower()
        if not base64_payload.startswith("data:"):
            raise APIError("invalid payload", 400, "invalid_payload")
        header, b64data = base64_payload.split(",", 1)
        if "base64" not in header:
            raise APIError("invalid payload", 400, "invalid_payload")
        try:
            raw = base64.b64decode(b64data, validate=True)
        except Exception as exc:
            raise APIError(f"decode failed: {exc}", 400, "invalid_payload")
        self._persist_media(conn, user, raw, declared_mime)

    def _upload_multipart(self, conn: sqlite3.Connection, user: dict[str, Any]) -> None:
        ctype = self.headers.get("Content-Type", "")
        boundary = None
        for part in ctype.split(";"):
            part = part.strip()
            if part.startswith("boundary="):
                boundary = part[len("boundary="):].strip('"')
                break
        if not boundary:
            raise APIError("missing boundary", 400, "invalid_payload")
        raw = self.read_bytes()
        # Parse exactly per RFC 7578. The body looks like:
        #   --boundary\r\n<headers>\r\n\r\n<part>\r\n--boundary\r\n<headers>...
        # ending with --boundary--\r\n. The previous implementation
        # used `body.rstrip(b"\r\n--")` which stripped by character set
        # and would corrupt any file whose final bytes were any
        # combination of \r \n -.
        delimiter = b"--" + boundary.encode()
        try:
            sections = raw.split(delimiter)
        except Exception:
            raise APIError("invalid multipart", 400, "invalid_payload")
        for section in sections:
            if not section or section.startswith(b"--"):
                # Either the leading empty chunk (before the first
                # delimiter) or the closing "--\r\n" marker.
                continue
            if section.startswith(b"\r\n"):
                section = section[2:]
            header_blob, sep, body = section.partition(b"\r\n\r\n")
            if not sep:
                continue
            headers_text = header_blob.decode("utf-8", errors="replace")
            if 'name="file"' not in headers_text:
                continue
            # Every part ends with the literal CRLF that precedes the
            # next delimiter. Strip exactly that — never use rstrip on
            # binary data.
            if body.endswith(b"\r\n"):
                body = body[:-2]
            mime_match = re.search(r"Content-Type:\s*([^\r\n]+)", headers_text)
            declared_mime = (mime_match.group(1).strip().lower() if mime_match else "")
            self._persist_media(conn, user, body, declared_mime)
            return
        raise APIError("no file part", 400, "invalid_payload")

    def _persist_media(
        self,
        conn: sqlite3.Connection,
        user: dict[str, Any],
        raw: bytes,
        declared_mime: str,
    ) -> None:
        if not raw:
            raise APIError("empty upload", 400, "invalid_payload")
        if len(raw) > MAX_UPLOAD_BYTES:
            raise APIError("file too large", 413, "too_large")
        sniffed = _sniff_mime(raw)
        if not sniffed:
            raise APIError("不支持的文件类型", 415, "unsupported_media")
        # Trust the bytes over the client-declared header. When the
        # declared mime is also in our allowlist and matches what we
        # sniffed, we use it for the canonical record. Otherwise fall
        # back to what the bytes say.
        mime = declared_mime if declared_mime in ALLOWED_MIME and declared_mime == sniffed else sniffed
        if mime not in ALLOWED_MIME:
            raise APIError("不支持的文件类型", 415, "unsupported_media")
        ext = EXT_BY_MIME.get(mime, ".bin")
        media_id = "file_" + uuid.uuid4().hex
        object_key = f"legacy/{user['id']}/{media_id}{ext}"
        target = local_upload_path(object_key)
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_bytes(raw)
        kind = "image" if mime.startswith("image/") else "video" if mime.startswith("video/") else "file"
        url = upload_public_url(object_key)
        thumb_url = upload_thumbnail_url(object_key, mime) or url
        now = now_iso()
        metadata = {
            "source": "legacy_media_upload",
            "thumbnail_url": thumb_url,
            "variants": {"original": url, "large": url, "medium": url, "thumbnail": thumb_url},
        }
        conn.execute(
            """
            INSERT INTO uploaded_files (
                id, upload_id, user_id, bucket, object_key, public_url, cdn_url, content_type,
                file_size, file_type, purpose, entity_type, entity_id, status, checksum, etag,
                metadata, created_at, updated_at
            )
            VALUES (?, ?, ?, 'local-dev', ?, ?, ?, ?, ?, ?, 'post_image', '', '', 'ready', ?, ?, ?, ?, ?)
            """,
            (
                media_id, "legacy_" + uuid.uuid4().hex, user["id"], object_key, url, url, mime,
                len(raw), upload_file_type(mime), hashlib.sha256(raw).hexdigest(),
                hashlib.md5(raw).hexdigest(), json.dumps(metadata, ensure_ascii=False, sort_keys=True), now, now,
            ),
        )
        # Width/height/duration intentionally default to 0 — the client
        # used to send these but they were unverified. A future pass
        # can compute them server-side with Pillow/ffprobe.
        conn.execute(
            "INSERT INTO media (id, owner_id, type, url, thumb_url, mime, width, height, duration, byte_size, created_at) VALUES (?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?)",
            (media_id, user["id"], kind, url, thumb_url, mime, len(raw), now),
        )
        record_upload_audit(conn, user["id"], "legacy_upload", file_id=media_id, status="ready", metadata={"bytes": len(raw), "mime": mime})
        fresh = dict(conn.execute("SELECT * FROM media WHERE id = ?", (media_id,)).fetchone())
        self.send_json({"media": serialize_media(fresh)})

    def api_admin_media(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 80), 300))
        kind = (query.get("type") or "").strip().lower()
        q = (query.get("q") or "").strip()
        clauses = ["m.deleted_at IS NULL"]
        params: list[Any] = []
        if kind:
            clauses.append("m.type = ?")
            params.append(kind)
        if q:
            like = f"%{q}%"
            clauses.append("(m.id LIKE ? OR m.mime LIKE ? OR m.url LIKE ? OR u.handle LIKE ? OR u.display_name LIKE ?)")
            params.extend([like, like, like, like, like])
        # scope=admin (default for the backend gallery): hide ordinary user
        # uploads, keep only admin-uploaded and system media.
        scope = (query.get("scope") or "").strip().lower()
        if scope == "admin":
            clauses.append("(u.role = 'admin' OR m.owner_id IS NULL OR m.owner_id = '')")
        where = "WHERE " + " AND ".join(clauses)
        rows = list(conn.execute(
            f"""
            SELECT m.*, u.handle AS owner_handle, u.display_name AS owner_name
              FROM media m
              LEFT JOIN users u ON u.id = m.owner_id
              {where}
             ORDER BY m.created_at DESC
             LIMIT ?
            """,
            [*params, limit],
        ))
        items = []
        for row in rows:
            item = serialize_media(dict(row))
            item["owner_handle"] = row["owner_handle"] or ""
            item["owner_name"] = row["owner_name"] or ""
            item["display_name"] = f"{item['type'].upper()} · {str(item['id'])[:8]}"
            items.append(item)
        self.send_json({"items": items})

    def api_admin_upload_media(self, conn: sqlite3.Connection) -> None:
        admin = self.require_admin(conn)
        ctype = self.headers.get("Content-Type", "")
        if "multipart/form-data" in ctype:
            self._upload_multipart(conn, admin)
            return
        self.api_upload_media(conn)

    def api_get_media(self, conn: sqlite3.Connection, media_id: str) -> None:
        row = conn.execute("SELECT * FROM media WHERE id = ? AND deleted_at IS NULL", (media_id,)).fetchone()
        if not row:
            raise APIError("媒体不存在", 404, "media_not_found")
        self.send_json({"media": serialize_media(dict(row))})

    def api_delete_media(self, conn: sqlite3.Connection, media_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM media WHERE id = ?", (media_id,)).fetchone()
        if not row or row["owner_id"] != user["id"]:
            raise APIError("无权操作", 403, "forbidden")
        conn.execute("UPDATE media SET deleted_at = ? WHERE id = ?", (now_iso(), media_id))
        conn.execute(
            "UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ? AND user_id = ?",
            (now_iso(), now_iso(), media_id, user["id"]),
        )
        self.send_json({"ok": True})

    def api_get_settings(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM settings WHERE user_id = ?", (user["id"],)).fetchone()
        if not row:
            conn.execute("INSERT INTO settings (user_id, updated_at) VALUES (?, ?)", (user["id"], now_iso()))
            row = conn.execute("SELECT * FROM settings WHERE user_id = ?", (user["id"],)).fetchone()
        data = dict(row)
        data["push_likes"] = bool(data["push_likes"])
        data["push_comments"] = bool(data["push_comments"])
        data["push_follows"] = bool(data["push_follows"])
        data["push_messages"] = bool(data["push_messages"])
        data["privacy_protect"] = bool(data["privacy_protect"])
        data["recommend_following"] = bool(data["recommend_following"])
        data["recommend_topics"] = bool(data["recommend_topics"])
        if data.get("appearance") not in ("light", "dark"):
            data["appearance"] = "light"
        self.send_json({"settings": data})

    def api_update_settings(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        allowed = {
            "language", "appearance", "push_likes", "push_comments", "push_follows", "push_messages",
            "privacy_protect", "privacy_allow_dm", "recommend_following", "recommend_topics",
        }
        updates: list[tuple[str, Any]] = []
        for key in allowed:
            if key in data:
                value = data[key]
                if key == "appearance" and value not in ("light", "dark"):
                    value = "light"
                if isinstance(value, bool):
                    value = 1 if value else 0
                updates.append((key, value))
        if updates:
            sets = ", ".join(f"{f} = ?" for f, _ in updates) + ", updated_at = ?"
            values = [v for _, v in updates] + [now_iso(), user["id"]]
            conn.execute(f"UPDATE settings SET {sets} WHERE user_id = ?", values)
        self.api_get_settings(conn)

    def api_clear_cache(self, conn: sqlite3.Connection) -> None:
        self.require_user(conn)
        self.send_json({"ok": True, "cleared_at": now_iso()})

    def api_export(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = list(conn.execute("SELECT * FROM posts WHERE author_id = ? AND deleted_at IS NULL", (user["id"],)))
        comments = list(conn.execute("SELECT * FROM comments WHERE author_id = ? AND deleted_at IS NULL", (user["id"],)))
        self.send_json({
            "exported_at": now_iso(),
            "user": serialize_user(user),
            "posts": [dict(r) for r in rows],
            "comments": [dict(r) for r in comments],
        })

    def api_feedback(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        conn.execute(
            "INSERT INTO feedback (id, user_id, category, content, created_at) VALUES (?, ?, ?, ?, ?)",
            (str(uuid.uuid4()), user["id"], data.get("category") or "general", (data.get("content") or "").strip(), now_iso()),
        )
        self.send_json({"ok": True})

    def api_devices(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = list(conn.execute(
            "SELECT * FROM sessions WHERE user_id = ? ORDER BY last_seen_at DESC",
            (user["id"],),
        ))
        grouped: dict[str, dict[str, Any]] = {}
        for r in rows:
            family, platform = _normalize_device_family(r["device_name"], r["user_agent"])
            group_key = f"{family}|{platform}"
            existing = grouped.get(group_key)
            geo = resolve_geo(r["ip"]) if r["ip"] else dict(_GEO_EMPTY)
            entry = {
                "id": r["token"][-12:],
                "token": r["token"],
                "tokens": [r["token"][-12:]],
                "device_name": r["device_name"] or family,
                "device_label": family,
                "platform": platform,
                "user_agent": r["user_agent"],
                "ip": r["ip"],
                "country": geo.get("country", ""),
                "region": geo.get("region", ""),
                "city": geo.get("city", ""),
                "org": geo.get("org", ""),
                "geo_state": geo.get("state", ""),
                "created_at": r["created_at"],
                "last_seen_at": r["last_seen_at"],
                "expires_at": r["expires_at"],
                "session_count": 1,
            }
            if not existing:
                grouped[group_key] = entry
                continue
            existing["session_count"] += 1
            existing["tokens"].append(r["token"][-12:])
            if (r["last_seen_at"] or "") > (existing["last_seen_at"] or ""):
                existing.update({
                    "id": r["token"][-12:],
                    "token": r["token"],
                    "device_name": r["device_name"] or family,
                    "user_agent": r["user_agent"],
                    "ip": r["ip"],
                    "country": geo.get("country", ""),
                    "region": geo.get("region", ""),
                    "city": geo.get("city", ""),
                    "org": geo.get("org", ""),
                    "geo_state": geo.get("state", ""),
                    "last_seen_at": r["last_seen_at"],
                    "expires_at": r["expires_at"],
                })
            if (r["created_at"] or "") < (existing["created_at"] or ""):
                existing["created_at"] = r["created_at"]
        items = sorted(grouped.values(), key=lambda x: x.get("last_seen_at") or "", reverse=True)
        self.send_json({"items": items})

    def api_revoke_device(self, conn: sqlite3.Connection, device_token: str) -> None:
        user = self.require_user(conn)
        conn.execute("DELETE FROM sessions WHERE user_id = ? AND (token = ? OR substr(token, length(token)-11) = ?)",
                     (user["id"], device_token, device_token))
        self.send_json({"ok": True})

    def api_list_drafts(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = conn.execute(
            "SELECT * FROM drafts WHERE user_id = ? ORDER BY updated_at DESC",
            (user["id"],),
        )
        items = []
        for r in rows:
            items.append({
                "id": r["id"],
                "content": r["content"],
                "media_ids": [m for m in (r["media_ids"] or "").split("|") if m],
                "tags": [t for t in (r["tags"] or "").split("|") if t],
                "updated_at": r["updated_at"],
            })
        self.send_json({"items": items})

    def api_save_draft(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        draft_id = data.get("id") or str(uuid.uuid4())
        media_ids = "|".join(data.get("media_ids") or [])
        tags = "|".join(data.get("tags") or [])
        existing = conn.execute("SELECT id FROM drafts WHERE id = ? AND user_id = ?", (draft_id, user["id"])).fetchone()
        if existing:
            conn.execute(
                "UPDATE drafts SET content = ?, media_ids = ?, tags = ?, updated_at = ? WHERE id = ?",
                (data.get("content") or "", media_ids, tags, now_iso(), draft_id),
            )
        else:
            conn.execute(
                "INSERT INTO drafts (id, user_id, content, media_ids, tags, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
                (draft_id, user["id"], data.get("content") or "", media_ids, tags, now_iso()),
            )
        self.send_json({"id": draft_id})

    def api_delete_draft(self, conn: sqlite3.Connection, draft_id: str) -> None:
        user = self.require_user(conn)
        conn.execute("DELETE FROM drafts WHERE id = ? AND user_id = ?", (draft_id, user["id"]))
        self.send_json({"ok": True})

    # ---- regions ----------------------------------------------------------

    def api_regions_countries(self, conn: sqlite3.Connection) -> None:
        """Full country list. Cached forever in-process (the data is a
        Python literal — it doesn't change at runtime)."""
        self.send_json({"items": REGION_COUNTRIES})

    def api_regions_provinces(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = (query.get("country") or "").strip().lower()
        if not country:
            raise APIError("country required", 400, "missing_param")
        provinces = REGION_PROVINCES.get(country, [])
        spec = _country_lookup(country)
        self.send_json({
            "country": country,
            "has_provinces": bool(spec and spec.get("has_provinces")),
            "items": provinces,
        })

    def api_regions_cities(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = (query.get("country") or "").strip().lower()
        province = (query.get("province") or "").strip().lower() or None
        if not country:
            raise APIError("country required", 400, "missing_param")
        spec = _country_lookup(country)
        if spec and spec.get("has_provinces"):
            allowed = {p["code"] for p in REGION_PROVINCES.get(country, [])}
            if not province or province not in allowed:
                self.send_json({"country": country, "province": province or "", "items": []})
                return
        cities = _cities_for_parent(country, province)
        self.send_json({"country": country, "province": province or "", "items": cities})

    def api_regions_popular(self, conn: sqlite3.Connection) -> None:
        """Resolve POPULAR_CITIES into rich objects (so the client can
        render `🇨🇳 上海` without re-walking the tree)."""
        items: list[dict[str, Any]] = []
        for code in POPULAR_CITIES:
            country_code, province_code, city_code = _parse_region_code(code)
            country = _country_lookup(country_code) or {}
            province_name = ""
            if province_code:
                for p in REGION_PROVINCES.get(country_code, []):
                    if p["code"] == province_code:
                        province_name = p["name"]
                        break
            city_name = ""
            for c in _cities_for_parent(country_code, province_code):
                if c["code"] == city_code:
                    city_name = c["name"]
                    break
            if not city_name:
                continue
            items.append({
                "region_code":   code,
                "country_code":  country_code,
                "country_name":  country.get("name", ""),
                "country_emoji": country.get("emoji", ""),
                "province_code": province_code,
                "province_name": province_name,
                "city_code":     city_code,
                "city_name":     city_name,
            })
        self.send_json({"items": items})

    def api_regions_resolve(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Look a region_code up and return the same hydrated shape as
        the popular list — used by the App / Web when displaying a
        post's location chip."""
        code = (query.get("code") or "").strip()
        if not code:
            raise APIError("code required", 400, "missing_param")
        country_code, province_code, city_code = _parse_region_code(code)
        country = _country_lookup(country_code) or {}
        province_name = ""
        if province_code:
            for p in REGION_PROVINCES.get(country_code, []):
                if p["code"] == province_code:
                    province_name = p["name"]
                    break
        if country.get("has_provinces") and not province_name:
            raise APIError("region not found", 404, "region_not_found")
        city_name = ""
        for c in _cities_for_parent(country_code, province_code):
            if c["code"] == city_code:
                city_name = c["name"]
                break
        if not city_name:
            raise APIError("region not found", 404, "region_not_found")
        self.send_json({
            "region_code":   code,
            "country_code":  country_code,
            "country_name":  country.get("name", ""),
            "country_emoji": country.get("emoji", ""),
            "province_code": province_code,
            "province_name": province_name,
            "city_code":     city_code,
            "city_name":     city_name,
        })

    def api_events_token(self, conn: sqlite3.Connection) -> None:
        """Exchange the long-lived Bearer for a short-lived SSE token.
        EventSource cannot attach an Authorization header so the Web
        client previously had to put the Bearer in the URL (`?token=`),
        which leaked it through nginx access logs / Referer / browser
        history. The new flow mints a one-shot token bound to the user
        that expires in 5 minutes."""
        user = self.require_user(conn)
        token = _mint_sse_token(user["id"])
        self.send_json({"token": token, "expires_in": int(_SSE_TOKEN_TTL)})

    def api_events(self, conn: sqlite3.Connection) -> None:
        # Resolve the user from either a one-shot SSE token (preferred,
        # via ?token=) or — for backwards compatibility — the standard
        # Bearer header. The long-lived Bearer in the URL is the
        # leakage vector we want to retire so the SSE-token path is
        # the documented one.
        parsed = urlparse(self.path)
        qs = parse_qs(parsed.query)
        sse_token = (qs.get("token") or [""])[0].strip()
        user_id = _consume_sse_token(sse_token)
        if user_id is None:
            user = self.require_user(conn)
            user_id = user["id"]
        self._pending_event_user_id = user_id
        return None

    # ---- marketing site copy ---------------------------------------------

    def _serialize_marketing_copy(self, row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
        d = dict(row)
        return {
            "id": d["id"],
            "page_key": d["page_key"],
            "locale": d["locale"],
            "title": d["title"],
            "body": d["body"],
            "status": d["status"],
            "sort_order": int(d["sort_order"] or 0),
            "created_at": d["created_at"],
            "updated_at": d["updated_at"],
        }

    def _clean_marketing_payload(self, data: dict[str, Any], *, partial: bool = False) -> dict[str, Any]:
        allowed_pages = {
            "home", "about", "features", "cities", "guide", "business", "safety", "download",
            "ads", "contact", "partners", "jobs-promotion", "housing-promotion",
            "updates", "faq", "safety-center", "privacy", "terms", "membership-terms",
            "service-terms", "refund-policy", "community-guidelines", "commercial-disclosure",
            "cookie-policy",
        }
        cleaned: dict[str, Any] = {}
        if "page_key" in data or not partial:
            page_key = str(data.get("page_key") or "").strip().lower()
            if page_key not in allowed_pages:
                raise APIError("页面不合法", 400, "invalid_page_key")
            cleaned["page_key"] = page_key
        if "locale" in data or not partial:
            locale = str(data.get("locale") or "zh").strip().lower()
            if locale not in ("zh", "en", "ja"):
                raise APIError("语言不合法", 400, "invalid_locale")
            cleaned["locale"] = locale
        if "title" in data or not partial:
            title = str(data.get("title") or "").strip()
            if not title:
                raise APIError("标题不能为空", 400, "invalid_title")
            cleaned["title"] = title[:160]
        if "body" in data or not partial:
            body = str(data.get("body") or "").strip()
            cleaned["body"] = body[:6000]
        if "status" in data or not partial:
            status = str(data.get("status") or "published").strip().lower()
            if status not in ("draft", "published"):
                raise APIError("状态不合法", 400, "invalid_status")
            cleaned["status"] = status
        if "sort_order" in data or not partial:
            try:
                cleaned["sort_order"] = max(0, min(int(data.get("sort_order") or 0), 9999))
            except (TypeError, ValueError):
                raise APIError("排序不合法", 400, "invalid_sort_order")
        return cleaned

    def api_marketing_copy(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        page_key = (query.get("page") or query.get("page_key") or "").strip().lower()
        locale = (query.get("locale") or "zh").strip().lower()
        if locale not in ("zh", "en", "ja"):
            locale = "zh"
        params: list[Any] = [locale]
        where = "WHERE status = 'published' AND locale = ?"
        if page_key:
            where += " AND page_key = ?"
            params.append(page_key)
        rows = list(conn.execute(
            f"SELECT * FROM marketing_copy {where} ORDER BY sort_order ASC, updated_at DESC LIMIT 50",
            params,
        ))
        self.send_json({"items": [self._serialize_marketing_copy(r) for r in rows]})

    def api_site_settings(self, conn: sqlite3.Connection) -> None:
        self.send_json({"settings": _site_settings(conn)})

    # ---- admin ------------------------------------------------------------
    #
    # Everything below requires the calling user to have `role = 'admin'`.
    # First-launched install: the first registered account is auto-promoted
    # to admin (see api_register). After that, only an existing admin can
    # mint another admin via PATCH /api/admin/users/:id { role: 'admin' }.

    def api_admin_stats(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        def one(sql: str, *p: Any) -> int:
            row = conn.execute(sql, p).fetchone()
            return int((row[0] if row else 0) or 0)

        cutoff_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
        cutoff_7d = (datetime.now(timezone.utc) - timedelta(days=7)).isoformat()
        stats = {
            "users_total":         one("SELECT COUNT(*) FROM users WHERE deleted_at IS NULL"),
            "users_24h":           one("SELECT COUNT(*) FROM users WHERE created_at > ?", cutoff_24h),
            "users_7d":            one("SELECT COUNT(*) FROM users WHERE created_at > ?", cutoff_7d),
            "posts_total":         one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL"),
            "posts_active":        one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND status IN ('published', 'active')"),
            "posts_under_review":  one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND status = 'under_review'"),
            "posts_hidden":        one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND status = 'hidden'"),
            "boosted_posts":       one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND is_boosted = 1"),
            "posts_24h":           one("SELECT COUNT(*) FROM posts WHERE created_at > ?", cutoff_24h),
            "comments_total":      one("SELECT COUNT(*) FROM comments WHERE deleted_at IS NULL"),
            "comments_24h":        one("SELECT COUNT(*) FROM comments WHERE created_at > ?", cutoff_24h),
            "messages_total":      one("SELECT COUNT(*) FROM messages WHERE deleted_at IS NULL"),
            "messages_24h":        one("SELECT COUNT(*) FROM messages WHERE created_at > ?", cutoff_24h),
            "media_total":         one("SELECT COUNT(*) FROM media WHERE deleted_at IS NULL"),
            "active_sessions":     one("SELECT COUNT(*) FROM sessions WHERE expires_at > ?", now_iso()),
            "reports_open":        one("SELECT COUNT(*) FROM reports"),
            "feedback_total":      one("SELECT COUNT(*) FROM feedback"),
            # Revenue + moderation aggregates for the 后台运营看板 (#6 看订单/看收入).
            "listings_total":          one("SELECT COUNT(*) FROM city_listings WHERE deleted_at IS NULL"),
            "listings_pending_review": one("SELECT COUNT(*) FROM city_listings WHERE deleted_at IS NULL AND status = 'pending_review'"),
            "listing_reports_open":    one("SELECT COUNT(*) FROM listing_reports WHERE status = 'open'"),
            "orders_paid_total":       one("SELECT COUNT(*) FROM payment_orders WHERE status = 'paid'"),
            "orders_pending":          one("SELECT COUNT(*) FROM payment_orders WHERE status = 'pending'"),
            "revenue_cents_total":     one("SELECT COALESCE(SUM(amount_cents), 0) FROM payment_orders WHERE status = 'paid'"),
            "revenue_cents_24h":       one("SELECT COALESCE(SUM(amount_cents), 0) FROM payment_orders WHERE status = 'paid' AND paid_at > ?", cutoff_24h),
            "revenue_cents_7d":        one("SELECT COALESCE(SUM(amount_cents), 0) FROM payment_orders WHERE status = 'paid' AND paid_at > ?", cutoff_7d),
            "active_memberships":      one("SELECT COUNT(*) FROM user_memberships WHERE status = 'active'"),
            "db_size_bytes":       (DB_PATH.stat().st_size if DB_PATH.exists() else 0),
            # Walking media/ on every admin stats request can be tens
            # of seconds with many files — cache it for 5 minutes.
            "media_size_bytes":    _cached_media_size_bytes(),
            "server_time":         now_iso(),
            "server_env":          "production" if PRODUCTION else "development",
            "allowed_origins":     sorted(ALLOWED_ORIGINS),
        }
        self.send_json({"stats": stats})

    def api_admin_server_metrics(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        self.send_json({"metrics": _server_metrics()})

    def api_admin_site_settings(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
